const QUESTIONS_CISA_C4 = [
  { id:21001, domain:4, level:1, question:"What does a service level agreement (SLA) primarily establish between an IT provider and its customer?", options:["A documented set of measurable service targets and the responsibilities each party agrees to meet","A technical network diagram detailing every router and switch deployed within the data center today","A vendor marketing brochure that lists optional add-on services available for future purchase later","An internal staffing roster identifying which administrators are on call during weekend shifts each month"], correct:0, explanation:"A network diagram is documentation, a brochure is marketing, and a roster is scheduling, none of which define measurable service commitments." },
  { id:21002, domain:4, level:1, question:"How does an operational level agreement (OLA) differ from a service level agreement (SLA)?", options:["An OLA is a legally binding contract signed only with third-party outsourcing vendors and suppliers","An OLA defines commitments between internal teams that support delivery of an externally promised SLA","An OLA sets penalties paid directly to end customers when agreed service targets are not achieved","An OLA replaces the SLA entirely once a service moves from development into full production operation"], correct:1, explanation:"Vendor contracts are underpinning contracts, customer penalties belong to the SLA, and an OLA supports rather than replaces the SLA." },
  { id:21003, domain:4, level:2, question:"An IS auditor reviewing SLA compliance should FIRST verify that the SLA contains which essential element?", options:["A clause requiring the provider to refresh all server hardware every three years without any exception","The personal mobile phone numbers of every senior executive employed by the contracted service provider","Specific, measurable metrics and thresholds against which actual service performance can be evaluated","A guarantee that the provider will never outsource any portion of the work to external subcontractors"], correct:2, explanation:"Without measurable metrics an SLA cannot be audited; hardware refresh, executive numbers, and subcontracting bans are not prerequisites for compliance." },
  { id:21004, domain:4, level:2, question:"Which ITIL process is responsible for restoring normal service operation as quickly as possible after a disruption?", options:["Change management, which controls and authorizes modifications to the production environment carefully","Capacity management, which ensures sufficient resources exist to meet current and future demand levels","Release management, which packages and deploys approved changes into the live operational environment","Incident management, which focuses on minimizing adverse impact and restoring service to users rapidly"], correct:3, explanation:"Change, capacity, and release management have distinct goals; only incident management is defined by rapid restoration after a disruption." },
  { id:21005, domain:4, level:2, question:"What is the PRIMARY objective of problem management as distinct from incident management?", options:["Identifying and eliminating the underlying root cause to prevent incidents from recurring in the future","Logging every user telephone call to the service desk so that reporting statistics remain fully complete","Approving emergency changes during a major outage so that the affected services are restored quickly","Scheduling routine preventive maintenance windows for hardware located within the primary data center"], correct:0, explanation:"Call logging is a service desk task, emergency approval is change management, and maintenance is operations; problem management targets root causes." },
  { id:21006, domain:4, level:3, question:"A provider consistently meets its SLA uptime target yet users report frequent dissatisfaction. What should the IS auditor MOST likely conclude?", options:["The users are uninformed and their complaints can be safely dismissed without any further analysis","The SLA metrics may not adequately reflect the service attributes that users actually value the most","The provider is deliberately falsifying its uptime reports to conceal repeated unplanned service outages","The SLA should be discarded because uptime is never a meaningful measure of service quality at all"], correct:1, explanation:"Dismissing users or assuming fraud is unsupported and uptime can be meaningful; the gap suggests metrics are misaligned with user expectations." },
  { id:21007, domain:4, level:1, question:"In ITIL, what is a known error?", options:["Any incident that the service desk was unable to resolve within the agreed first-response time window","A change request that was rejected by the advisory board because of an unacceptable level of technical risk","A problem with a documented root cause and a workaround that has been identified and formally recorded","A configuration item that has been formally retired and removed from the live operational estate already"], correct:2, explanation:"Unresolved incidents, rejected changes, and retired items are different; a known error specifically has a documented cause and workaround." },
  { id:21008, domain:4, level:2, question:"Which document best supports measuring whether an internal network team meets commitments needed to fulfill a customer SLA?", options:["The customer's signed purchase order authorizing payment for the contracted service offering each year","The data center's physical visitor log recording all entries and exits over the prior calendar month","The provider's published annual financial statement disclosing its total revenue and net profit figures in practice","The operational level agreement that the network team signed with the service delivery function internally"], correct:3, explanation:"A purchase order, visitor log, and financial statement are unrelated to internal team commitments; the OLA captures the supporting internal targets." },
  { id:21009, domain:4, level:2, question:"An underpinning contract (UC) in service management governs what relationship?", options:["The agreement between the service provider and an external third-party supplier supporting a service","The agreement between two business units of the same organization sharing a common IT platform daily","The agreement between end users and the service desk regarding acceptable telephone call hold times","The agreement between auditors and management defining the scope of an upcoming control review engagement"], correct:0, explanation:"Internal unit agreements are OLAs, user-desk expectations are SLA matters, and audit scope is an engagement letter; a UC governs external suppliers." },
  { id:21010, domain:4, level:3, question:"Why might tracking only mean time to repair (MTTR) give an incomplete picture of operational resilience?", options:["It is impossible to calculate accurately because repair durations can never be measured with any precision","It measures recovery speed but ignores how frequently failures occur, captured by mean time between failures","It applies exclusively to software defects and therefore has no relevance to any hardware component at all","It always overstates availability because vendors deliberately inflate every repair time figure they report as a rule"], correct:1, explanation:"MTTR can be measured and applies broadly; the real limitation is that it omits failure frequency, which MTBF captures, so both are needed." },
  { id:21011, domain:4, level:2, question:"What is the main purpose of a service catalog in IT service management?", options:["Storing the encrypted password hashes for every administrative account used across the environment now","Recording the precise serial numbers and warranty dates of all physical assets in the data center","Providing a structured, customer-facing list of the live services available along with their key details","Archiving the source code of all internally developed applications for long-term legal preservation later"], correct:2, explanation:"Password storage, asset serials, and source code archiving are separate functions; the service catalog presents available services to customers." },
  { id:21012, domain:4, level:1, question:"What does availability typically refer to in an SLA context?", options:["The total number of distinct features that a software application offers to its registered end users","The maximum number of concurrent administrators permitted to log into a single server simultaneously","The geographic distance between the primary data center and the designated alternate recovery site","The proportion of agreed time during which a service is operational and accessible to its users"], correct:3, explanation:"Feature counts, admin limits, and site distance are unrelated; availability measures the percentage of agreed time the service is usable." },
  { id:21013, domain:4, level:2, question:"During a service review, which trend would MOST concern an IS auditor about problem management effectiveness?", options:["A steadily rising number of repeat incidents traced to the same unresolved underlying root cause","A gradual decrease in the average number of new feature requests submitted by business users monthly","An increase in the volume of routine password reset requests handled by the service desk team daily","A reduction in the number of planned maintenance windows scheduled during off-peak weekend hours"], correct:0, explanation:"Fewer feature requests, more resets, and fewer maintenance windows are not problem-management failures; recurring root-cause incidents are." },
  { id:21014, domain:4, level:2, question:"Which metric best reflects how quickly a service desk resolves user-reported incidents?", options:["Total headcount of staff currently employed across the entire information technology department now in turn","Mean time to resolve, measuring the average elapsed time from incident logging to confirmed restoration","The annual licensing cost of the ticketing system used to record and track every reported incident","The number of physical telephones installed at the desks within the service desk operations area"], correct:1, explanation:"Headcount, license cost, and phone counts do not measure resolution speed; mean time to resolve directly captures it." },
  { id:21015, domain:4, level:3, question:"An organization wants SLA penalties to drive supplier behavior. What design flaw should an IS auditor watch for?", options:["Penalty clauses written in clear language that both parties reviewed and understood before they signed each time","Metrics that are objectively measured using data drawn directly from the central monitoring platform","Penalty thresholds set so leniently that the supplier can routinely miss targets without any consequence","Reporting that is delivered to both the customer and supplier on a consistent monthly review schedule"], correct:2, explanation:"Clear clauses, objective metrics, and consistent reporting are strengths; lenient thresholds that allow misses without penalty undermine the incentive." },
  { id:21016, domain:4, level:1, question:"What is the role of a configuration management database (CMDB)?", options:["Generating the monthly invoices that the finance department sends to its external paying customers","Filtering inbound email messages to block phishing attempts before they reach individual user mailboxes","Encrypting backup tapes before they are transported to a secure offsite storage facility each week","Maintaining records of configuration items and the relationships among the components of IT services"], correct:3, explanation:"Invoicing, email filtering, and tape encryption are unrelated functions; the CMDB records configuration items and their interrelationships." },
  { id:21017, domain:4, level:2, question:"Why is linking incidents to configuration items in a CMDB valuable?", options:["It helps identify which components are most failure-prone and supports faster impact analysis during outages","It automatically eliminates the need to ever perform any root-cause analysis on recurring incidents again by design","It guarantees that no change will ever be deployed without first obtaining full executive board approval","It replaces the requirement to maintain backups because the relationships themselves preserve all data"], correct:0, explanation:"Linking does not remove root-cause analysis, force board approval, or replace backups; it reveals failure-prone components and speeds impact analysis." },
  { id:21018, domain:4, level:2, question:"An IS auditor finds the service catalog has not been updated in two years. What is the MOST significant risk?", options:["The catalog will consume excessive disk storage space because of its accumulated historical version records","Users and support staff may rely on inaccurate service information, leading to misdirected requests and errors","The font and color scheme of the catalog may appear outdated relative to current corporate branding guidelines","Suppliers may refuse to sign new underpinning contracts until the catalog formatting is fully modernized"], correct:1, explanation:"Storage, fonts, and supplier signatures are trivial or unrelated; the real risk is reliance on stale, inaccurate service information." },
  { id:21019, domain:4, level:3, question:"How should an IS auditor evaluate whether continual service improvement (CSI) is operating effectively?", options:["By counting how many meetings the improvement team holds each month regardless of any resulting outcomes up front","By verifying that the organization has purchased the most expensive service management tooling available","By confirming that measured performance gaps lead to documented, tracked improvement actions with clear owners","By ensuring that no service metric has ever shown a decline at any point during the entire review period"], correct:2, explanation:"Meeting counts, tool cost, and never declining are poor proxies; CSI effectiveness shows in gaps driving tracked, owned improvement actions." },
  { id:21020, domain:4, level:2, question:"What is the purpose of a service desk in IT operations?", options:["Designing the long-term enterprise architecture roadmap for all future technology investments and projects","Approving the annual capital budget for purchasing new servers and storage within the data center","Writing the program code for the organization's customer-facing mobile and web application products","Acting as the single point of contact for users to report incidents and request services and support"], correct:3, explanation:"Architecture, budgeting, and coding are separate functions; the service desk is the single point of contact for incidents and requests." },
  { id:21021, domain:4, level:1, question:"What is the primary goal of change management in IT operations?", options:["Ensuring changes are assessed, approved, and implemented in a controlled way to minimize service disruption","Guaranteeing that every proposed change is implemented immediately upon request without any prior review for them","Reducing the total number of staff required to operate the production data center on a daily basis","Encrypting all data at rest so that unauthorized parties cannot read information stored on disk drives"], correct:0, explanation:"Immediate unreviewed changes contradict control, and staff reduction and encryption are unrelated; controlled, low-disruption change is the goal." },
  { id:21022, domain:4, level:2, question:"Which control BEST reduces the risk of unauthorized changes reaching production?", options:["Requiring developers to write longer and more detailed comments inside the application source code files","Segregation of duties so those who develop changes cannot also approve and deploy them into production","Increasing the frequency of full backups taken of the production database every single business day","Installing additional physical security cameras at every entrance to the primary data center facility"], correct:1, explanation:"Comments, backups, and cameras do not prevent unauthorized deployment; separating development from approval and deployment does." },
  { id:21023, domain:4, level:2, question:"What is an emergency change, and what control is essential for it?", options:["A routine cosmetic change that can be deployed at any time without recording it in any change log at all","A change that bypasses all review permanently because emergencies are exempt from governance requirements","An urgent change to restore service that still requires retrospective documentation and review after the fact","A scheduled change planned weeks in advance and approved through the standard change advisory board process at times"], correct:2, explanation:"Emergency changes are urgent, not cosmetic or pre-planned, and never permanently exempt; retrospective review is the essential control." },
  { id:21024, domain:4, level:3, question:"An IS auditor finds that 30% of production changes last quarter were classified as emergency changes. What is the MOST appropriate concern?", options:["The organization is clearly too cautious and should reclassify even more of its standard changes as emergencies","Emergency changes are inherently safer than standard changes, so a high rate is a positive indicator overall","The figure is irrelevant because change classification has no bearing on the reliability of production systems","The high emergency rate may indicate weak planning that bypasses normal review and elevates operational risk"], correct:3, explanation:"Emergencies are not safer and the rate is relevant; a high proportion suggests normal controls are being bypassed, raising risk." },
  { id:21025, domain:4, level:1, question:"What is the purpose of a change advisory board (CAB)?", options:["Reviewing and authorizing significant changes by assessing their risk, impact, and readiness before deployment","Physically installing new server hardware into the racks located within the primary data center facility as well","Writing the detailed program code required to implement each approved application enhancement request","Answering inbound user telephone calls reporting incidents and logging them into the ticketing system"], correct:0, explanation:"Installing hardware, coding, and answering calls are operational tasks; the CAB reviews and authorizes significant changes." },
  { id:21026, domain:4, level:2, question:"Why should production changes be tested in a separate environment before deployment?", options:["To increase the total number of servers the organization owns and thereby raise its overall asset valuation","To detect defects and unintended effects without risking disruption to live services used by the business","To ensure that developers gain administrative access rights to the live production environment directly","To eliminate the need for any change approval because successful testing makes approval unnecessary now"], correct:1, explanation:"Testing does not exist to inflate asset counts, grant production access, or remove approval; it catches defects before production." },
  { id:21027, domain:4, level:2, question:"What is the key benefit of maintaining a back-out (rollback) plan for changes?", options:["It permanently prevents the same change from ever needing to be attempted again at any point in the future","It removes the requirement to test the change because rollback covers any possible defect after deployment","It allows the environment to be restored to its prior working state if a change causes unexpected problems","It automatically notifies all affected end users by email whenever a change has been fully completed"], correct:2, explanation:"Rollback does not block future attempts, replace testing, or send notifications; it restores the prior state when a change fails." },
  { id:21028, domain:4, level:3, question:"During a change audit, the auditor notes test results are attached to change records but never reviewed by the approver. What is the BEST conclusion?", options:["The process is fully effective because the presence of attached test results alone guarantees quality outcomes","Reviewing test results is unnecessary since the change advisory board already meets on a regular weekly schedule too","The finding is immaterial because approvers are not qualified to interpret technical test result documents","Approval occurs without evidence-based assessment, weakening the assurance the change process is meant to provide"], correct:3, explanation:"Mere attachment without review provides no assurance; approvers ignoring evidence means approval is not evidence-based, the weakness." },
  { id:21029, domain:4, level:1, question:"What does patch management primarily aim to achieve?", options:["Applying vendor updates in a controlled manner to remediate vulnerabilities and defects in software","Increasing the screen resolution of user workstations to improve the clarity of the displayed text","Reducing the electrical power consumed by servers operating within the primary data center facility","Renaming network shares so that their folder structure better matches departmental naming conventions"], correct:0, explanation:"Screen resolution, power use, and share naming are unrelated; patch management applies updates to fix vulnerabilities and defects." },
  { id:21030, domain:4, level:2, question:"Why should patches be tested before broad deployment in production?", options:["Because testing a patch automatically extends the software vendor's warranty for an additional full year over time","Because a patch can introduce incompatibilities or break functionality that disrupts critical business services","Because untested patches are guaranteed by the vendor to be completely free of any defects whatsoever","Because regulators prohibit any organization from ever deploying a software patch in a production system"], correct:1, explanation:"Testing does not extend warranties, patches are not defect-free, and deployment is not prohibited; testing prevents disruptive incompatibilities." },
  { id:21031, domain:4, level:2, question:"An organization delays applying a critical security patch for several months. What is the PRIMARY risk?", options:["The vendor may charge a higher annual subscription fee because the patch was not applied promptly enough","The user interface of the affected application may appear visually outdated compared with the newer releases up front","Attackers may exploit the known unpatched vulnerability to compromise systems during the extended exposure window","The organization may accumulate too many patch files awaiting deployment in its software distribution server"], correct:2, explanation:"Subscription fees, visual aging, and file accumulation are minor; the primary risk is exploitation of the known vulnerability during the delay." },
  { id:21032, domain:4, level:3, question:"How should an IS auditor assess whether a patch management process balances security and stability?", options:["By confirming that every available patch is deployed within minutes of release regardless of any testing outcomes too","By ensuring that the organization deliberately delays all patches for a fixed ninety-day stabilization period","By checking only that the patch server has sufficient free disk space to store all downloaded patch files","By verifying that patches are risk-prioritized, tested proportionately to risk, and deployed within defined timelines"], correct:3, explanation:"Instant deployment without testing risks stability, blanket delays risk security, and disk space is trivial; risk-based prioritization balances both." },
  { id:21033, domain:4, level:1, question:"What is release management responsible for?", options:["Planning, building, and deploying approved changes into production as coordinated, tested release packages","Negotiating the financial terms of contracts with external cloud infrastructure hosting providers each year","Conducting background screening checks on candidates applying for data center operator positions","Designing the physical cooling and airflow layout for the server racks inside the data center hall"], correct:0, explanation:"Contract terms, screening, and cooling design are unrelated; release management coordinates building and deploying approved changes." },
  { id:21034, domain:4, level:2, question:"Why is version control important in release management?", options:["It permanently prevents developers from ever modifying any source code after it has been written one time","It ensures the correct, approved version of each component is deployed and supports recovery to a known good state","It removes the need for change approval because tracked versions are automatically considered fully authorized as a rule","It guarantees that the software will never contain any defects once it is placed under version control"], correct:1, explanation:"Version control does not freeze code, authorize changes, or eliminate defects; it ensures the right version is deployed and enables recovery." },
  { id:21035, domain:4, level:2, question:"A developer deploys code directly to production using shared administrator credentials. Which control is MOST clearly missing?", options:["A faster internet connection between the developer workstation and the production server environment used","A larger monitor for the developer to view many more lines of source code at one time while working","Individual accountability and segregation of duties enforced through unique, role-restricted access credentials","An additional uninterruptible power supply unit installed to protect the production database server itself at times"], correct:2, explanation:"Connection speed, monitor size, and a UPS are irrelevant; shared credentials with direct deployment defeat accountability and segregation of duties." },
  { id:21036, domain:4, level:3, question:"An auditor reviews a release that succeeded technically but caused user confusion due to unannounced interface changes. What gap does this MOST indicate?", options:["The release should have been rejected because any change to a user interface is inherently always prohibited too","The technical testing was insufficient even though the release functioned exactly as it was designed to","The rollback plan was unnecessary and should be removed from all future release planning documentation","Inadequate communication and stakeholder readiness activities within the release management process were missing"], correct:3, explanation:"UI changes are not prohibited, testing was adequate since it worked, and rollback remains valuable; the gap is missing communication and readiness." },
  { id:21037, domain:4, level:1, question:"What is a standard change in change management?", options:["A pre-authorized, low-risk, repeatable change that follows a documented procedure without case-by-case approval","A high-risk emergency change that must always interrupt the change advisory board's regular meeting agenda as well","A change that has never been performed before and whose outcome is completely unknown to the team","A change that can only be performed by the most senior executive within the entire organization itself"], correct:0, explanation:"Standard changes are low-risk and repeatable, not emergency, novel, or executive-only; they are pre-authorized and follow a set procedure." },
  { id:21038, domain:4, level:2, question:"Why should change records include the identity of the person who implemented each change?", options:["To calculate the annual salary bonus that each implementer is entitled to receive at the end of the year","To support accountability and enable investigation if a change later contributes to an incident or failure","To determine which implementer should be granted the largest office space within the headquarters building","To rank implementers publicly by the total number of changes they completed during the prior quarter"], correct:1, explanation:"Bonuses, office space, and public ranking are not control purposes; recording the implementer supports accountability and investigation." },
  { id:21039, domain:4, level:3, question:"An organization uses automated deployment pipelines. What new audit consideration does this introduce versus manual changes?", options:["Whether the pipeline software has an attractive graphical dashboard that managers genuinely enjoy looking at each time","Whether developers prefer using the pipeline over the previous manual deployment process they once used","Whether pipeline approval gates, access controls, and audit logging adequately replace prior manual control points","Whether the pipeline can deploy changes faster than any competing organization in the same industry sector"], correct:2, explanation:"Dashboard appeal, preference, and relative speed are not control concerns; the auditor must confirm automated gates and logging preserve controls." },
  { id:21040, domain:4, level:2, question:"Why should a freeze period be considered during critical business cycles such as year-end?", options:["A freeze period guarantees that no system will experience any failure at all during the busy year-end cycle as noted","Freezing changes is required so the change team can take its annual vacation leave at the same time","A freeze period exists primarily to reduce the electricity consumed by the production servers at year-end","Restricting non-essential changes during peak periods reduces the risk of disruption to vital business processing"], correct:3, explanation:"A freeze does not guarantee zero failures, enable vacations, or cut power; it limits non-essential changes to reduce disruption risk during peaks." },
  { id:21041, domain:4, level:1, question:"What is the primary purpose of a job scheduling system in IT operations?", options:["Automating the timely execution of batch processes in the correct sequence and at the appropriate times","Encrypting all network traffic flowing between the data center and the remote branch office locations by design","Designing the user interface layout for new web applications under active development by the team","Recruiting and onboarding new operations staff to work shifts in the data center control room daily"], correct:0, explanation:"Encryption, UI design, and recruiting are unrelated; job scheduling automates batch execution in proper sequence and timing." },
  { id:21042, domain:4, level:2, question:"Why is monitoring batch job completion important in operations?", options:["Monitoring batch jobs increases the resale value of the servers on which the various jobs are executed","A failed or incomplete batch job can corrupt data or delay dependent processes if it is not detected promptly","Watching batch jobs run is the only way to keep operations staff alert and awake during overnight shifts over time","Batch job logs are the primary source used to calculate the data center's total monthly electricity bill"], correct:1, explanation:"Resale value, alertness, and electricity bills are not the reason; undetected batch failures can corrupt data and delay dependent processes." },
  { id:21043, domain:4, level:2, question:"An IS auditor finds batch job failures are logged but no one is assigned to review the logs. What is the MAIN risk?", options:["The log files will eventually grow large enough to slow the loading of unrelated everyday office documents","Operations staff may become bored because reviewing logs would have given them additional daily duties","Job failures may go unnoticed and unresolved, allowing data errors or processing delays to propagate undetected","The organization may be required to purchase a second logging server to store the duplicate failure records up front"], correct:2, explanation:"Document loading, boredom, and a second server are not the main risk; without review, failures go unresolved and errors propagate." },
  { id:21044, domain:4, level:3, question:"How should job dependencies be handled to maintain processing integrity?", options:["All jobs should always start at exactly the same moment to finish the overall batch as fast as possible in practice","Dependencies should be ignored because modern hardware is fast enough to absorb any ordering problems","Each job should be run twice in parallel so that at least one copy is guaranteed to finish correctly","A dependent job should be configured not to start until its prerequisite jobs have completed successfully"], correct:3, explanation:"Simultaneous starts, ignoring order, and double-running risk corruption; integrity requires dependent jobs to wait for successful prerequisites." },
  { id:21045, domain:4, level:1, question:"What does event management in IT operations primarily involve?", options:["Detecting, categorizing, and responding to notable occurrences such as alerts and threshold breaches","Organizing the annual holiday party and other social gatherings for information technology staff members","Negotiating the purchase price of new laptops for employees joining the organization each fiscal quarter","Drafting the corporate marketing strategy used to attract new customers to the company's products"], correct:0, explanation:"Parties, purchasing, and marketing are unrelated; event management detects, categorizes, and responds to notable IT occurrences." },
  { id:21046, domain:4, level:2, question:"Why should monitoring thresholds be set thoughtfully rather than arbitrarily?", options:["Thresholds determine the physical temperature at which the data center cooling units will automatically activate","Thresholds set too low generate excessive false alarms, while thresholds set too high may miss real problems","Thresholds control how many employees are permitted to access the building during normal business hours","Thresholds set the maximum salary that can be offered to candidates for monitoring analyst job roles"], correct:1, explanation:"Thresholds do not govern cooling, building access, or salaries; poorly set thresholds cause either alert fatigue or missed problems." },
  { id:21047, domain:4, level:2, question:"What is alert fatigue and why does it concern an IS auditor?", options:["A hardware failure that occurs when a monitoring server processes far too many alerts in a single day","A licensing limit that prevents the monitoring tool from generating more than a fixed number of alerts","A condition where excessive alerts desensitize staff, raising the chance that a genuine alert is overlooked","A scheduling conflict that arises when two monitoring analysts are assigned to the same work shift period at times"], correct:2, explanation:"It is not a hardware failure, license limit, or scheduling conflict; alert fatigue is desensitization that causes real alerts to be missed." },
  { id:21048, domain:4, level:3, question:"An organization monitors server CPU and memory but not application response times. What blind spot does this create?", options:["The monitoring system will be unable to record the physical serial numbers of the monitored server hardware too","The organization will be unable to calculate the depreciation schedule for its server hardware assets","Administrators will lose the ability to remotely restart the servers when an operating system fully hangs","Users may experience poor application performance even while the infrastructure metrics appear entirely healthy"], correct:3, explanation:"Serial numbers, depreciation, and remote restart are unrelated; without application metrics, user-facing slowness can occur while infrastructure looks fine." },
  { id:21049, domain:4, level:1, question:"What is the purpose of an operations runbook?", options:["Providing documented, repeatable procedures so operators can perform routine and recovery tasks consistently","Recording the personal vacation preferences of every member of the operations support team each year","Listing the retail price of every software product the organization has purchased over the past years","Storing photographs of the data center taken during its original construction and grand opening ceremony as well"], correct:0, explanation:"Vacation preferences, prices, and photos are not its purpose; a runbook documents repeatable operational and recovery procedures." },
  { id:21050, domain:4, level:2, question:"Why is restricting access to the job scheduler an important control?", options:["The job scheduler consumes significant electricity, so limiting access noticeably reduces the data center power bill","Unauthorized changes to schedules could disrupt processing, alter sequences, or run jobs at improper times","Restricting access makes the scheduler's user interface appear far more visually appealing to the operators","Fewer users with access means the software vendor will offer a larger discount on the annual license cost"], correct:1, explanation:"Power, appearance, and discounts are irrelevant; restricting scheduler access prevents disruptive or improper changes to processing." },
  { id:21051, domain:4, level:2, question:"An IS auditor observes that operators can modify production data directly to fix failed jobs. What is the PRIMARY concern?", options:["Operators may take longer to fix the jobs than developers would have taken to fix the very same issue","The practice may cause operators to feel overworked and then request additional compensation later on","Direct data modification bypasses application controls and audit trails, risking undetected errors or manipulation","Direct fixes might use a command-line tool that is harder to learn than a friendly graphical interface in practice"], correct:2, explanation:"Time, workload, and tool difficulty are minor; bypassing application controls and audit trails risks undetected errors or manipulation." },
  { id:21052, domain:4, level:3, question:"How can an IS auditor verify that scheduled jobs actually ran as intended over a period?", options:["By asking the operations manager whether everything generally seemed fine during the entire review period","By confirming that the scheduling software was the most recent version currently available from the vendor","By counting the number of operators who were present in the control room during the overnight shift periods as noted","By comparing the scheduler's execution logs against the expected schedule and investigating any exceptions found"], correct:3, explanation:"Verbal assurance, software version, and staff counts do not prove execution; comparing execution logs to the schedule and reviewing exceptions does." },
  { id:21053, domain:4, level:1, question:"What is end-user computing (EUC)?", options:["Applications and tools, such as spreadsheets and databases, developed and used directly by business users","The centralized mainframe processing performed exclusively by the core IT operations department each day by design","The physical network cabling that connects the user workstations to the building's floor wiring closets","The corporate policy that governs how employees may use company vehicles for official business travel"], correct:0, explanation:"Mainframe processing, cabling, and vehicle policy are unrelated; EUC refers to applications built and used by business users themselves." },
  { id:21054, domain:4, level:2, question:"Why do end-user-developed spreadsheets pose a control risk?", options:["They consume far more disk space than equivalent applications written by the central IT department staff","They often lack formal testing, version control, and change controls, so errors can go undetected and propagate","They can only be opened on the specific workstation where they were originally created by the first user","They automatically expire and become completely unusable after a fixed period defined by the spreadsheet vendor"], correct:1, explanation:"Disk space, portability, and expiration are not the issue; EUC tools typically lack testing and change controls, so errors propagate undetected." },
  { id:21055, domain:4, level:3, question:"An IS auditor finds a critical financial report depends on an undocumented spreadsheet maintained by one employee. What is the GREATEST concern?", options:["The spreadsheet may use a color scheme that does not match the organization's official corporate branding palette too","The employee may have spent too many hours building the spreadsheet instead of attending regular team meetings","Key-person dependency and lack of documentation threaten continuity and accuracy if that employee becomes unavailable","The spreadsheet file name may not follow the organization's preferred internal document naming convention rules"], correct:2, explanation:"Color, hours, and naming are trivial; reliance on one undocumented spreadsheet creates key-person and accuracy risks for a critical report." },
  { id:21056, domain:4, level:2, question:"Which control would BEST reduce risk in critical end-user computing applications?", options:["Banning all spreadsheets across the entire organization regardless of how trivial or simple their purpose is in practice","Allowing only the chief executive officer to open any spreadsheet stored anywhere on the corporate network","Converting every spreadsheet into a printed paper document and then discarding the electronic source version","Inventorying critical EUC tools and applying proportionate testing, access, and change controls to each of them"], correct:3, explanation:"A total ban, CEO-only access, and paper conversion are impractical extremes; inventorying and applying proportionate controls manages the risk." },
  { id:21057, domain:4, level:1, question:"What is the purpose of capacity management?", options:["Ensuring that IT resources are sufficient to meet current and anticipated future demand cost-effectively","Designing the artwork and layout used on the organization's public-facing marketing website pages","Approving travel expense claims submitted by employees within the information technology department","Selecting the background music to be played in the data center during regular working hours each day for them"], correct:0, explanation:"Website art, expenses, and music are unrelated; capacity management ensures resources meet present and future demand efficiently." },
  { id:21058, domain:4, level:2, question:"Why is trend analysis useful in capacity management?", options:["It identifies which employees use the most coffee in the office kitchen during regular business hours as a rule","It projects future resource needs from historical usage so upgrades can be planned before any shortages occur","It calculates the exact resale value of decommissioned servers sold to second-hand equipment buyers","It determines the color of the warning lights installed on the front of each rack in the data center"], correct:1, explanation:"Coffee, resale value, and light color are irrelevant; trend analysis forecasts future needs so capacity is added before shortages hit." },
  { id:21059, domain:4, level:3, question:"An organization repeatedly experiences performance degradation at month-end. What capacity weakness does this MOST suggest?", options:["The servers are physically too heavy and are slowly sinking into the data center floor over time gradually","The month-end date is calculated incorrectly, causing the jobs to run on the wrong calendar day each time","Capacity planning has not accounted for predictable peak demand cycles such as month-end processing loads","Employees are intentionally overloading the systems at month-end to justify requesting brand new equipment"], correct:2, explanation:"Physical weight, date errors, and sabotage are implausible; recurring month-end slowness shows planning ignored a predictable peak demand cycle." },
  { id:21060, domain:4, level:1, question:"What is the primary purpose of data backups?", options:["Permanently deleting old data so that the storage systems never run out of available free disk space","Increasing the speed at which users can open and edit files on their local workstations during the day","Encrypting network traffic exchanged between branch offices and the central corporate data center","Creating recoverable copies of data so it can be restored after loss, corruption, or a disaster event"], correct:3, explanation:"Backups do not delete data, speed file access, or encrypt traffic; they create recoverable copies for restoration after loss." },
  { id:21061, domain:4, level:2, question:"Why is periodically testing the restoration of backups essential?", options:["A backup is only useful if it can be restored, and testing confirms the data is actually recoverable and intact","Testing restoration noticeably increases the total storage capacity available on the backup media being used as well","Restoration testing is required to keep the backup software's graphical user interface running smoothly","Testing restores allows the organization to delete the original production data to save valuable disk space"], correct:0, explanation:"Restoration tests do not add capacity, maintain the UI, or justify deleting production data; they prove backups are actually recoverable." },
  { id:21062, domain:4, level:2, question:"An organization performs nightly backups but has never tested a restore. What is the PRIMARY risk?", options:["The backup media may eventually become too heavy to carry to the offsite storage location each week","Backups may be incomplete or corrupted and unrecoverable, leaving the organization unable to recover when needed","The nightly backup window may overlap slightly with the very start of the morning business day each time in turn","The backup software vendor may release a newer version with a slightly different user interface layout"], correct:1, explanation:"Media weight, window overlap, and UI changes are minor; untested backups may be unrecoverable exactly when they are needed." },
  { id:21063, domain:4, level:3, question:"Why is storing backups offsite or in a separate location important for resilience?", options:["Offsite storage is always cheaper than keeping the backup media within the primary data center facility itself","Moving backups offsite reduces the physical weight of all equipment stored within the primary data center","A disaster affecting the primary site could destroy both production data and onsite backups simultaneously","Offsite backups load and restore faster than backups that are kept close to the production environment"], correct:2, explanation:"Cost, weight, and speed are not the rationale; offsite copies survive a disaster that could destroy both production and local backups together." },
  { id:21064, domain:4, level:1, question:"What does a full backup capture?", options:["Only the data that has changed since the most recent backup of any type was successfully performed","Only the data that has changed since the most recent full backup was last successfully performed","Only the operating system files while deliberately excluding all of the user-created data documents","A complete copy of all selected data regardless of whether it has changed since the previous backup"], correct:3, explanation:"Changed-only-since-any is incremental, changed-since-full is differential, and OS-only is wrong; a full backup copies all selected data." },
  { id:21065, domain:4, level:2, question:"How does an incremental backup differ from a differential backup?", options:["An incremental copies data changed since the last backup, while a differential copies changes since the last full","An incremental copies everything every single time, while a differential copies only the operating system files","An incremental is always stored offsite, while a differential must always be stored onsite at the primary location","An incremental can only be restored once, while a differential can be restored an unlimited number of times"], correct:0, explanation:"Storage location and restore counts are not the distinction; incremental copies changes since any last backup, differential since the last full." },
  { id:21066, domain:4, level:3, question:"An organization uses weekly full backups plus daily incrementals. To fully restore Thursday's data, what is required?", options:["Only Thursday's incremental backup is needed because it already contains every change made during that week","The last full backup plus each incremental taken in sequence up to and including Thursday's incremental backup","Only the most recent full backup is needed because the incrementals are merely optional supplementary copies over time","Any single incremental from the week is sufficient because all the incrementals contain identical data sets"], correct:1, explanation:"A single incremental is insufficient and incrementals are not identical or optional; restoring requires the full plus each incremental in order." },
  { id:21067, domain:4, level:2, question:"What is the purpose of a backup retention policy?", options:["Determining the physical color of the labels that are attached to the backup tapes stored in the media library up front","Specifying which particular brand of backup software must be purchased for the organization's data center","Defining how long backups are kept to balance recovery needs, storage cost, and legal or regulatory requirements","Setting the room temperature at which the backup tape storage cabinet should be maintained at all times"], correct:2, explanation:"Label color, software brand, and temperature are not its function; a retention policy sets how long backups are kept balancing recovery, cost, and law." },
  { id:21068, domain:4, level:2, question:"An IS auditor finds backup tapes transported offsite in an unlocked, unmarked vehicle by a junior clerk. What is the PRIMARY concern?", options:["The junior clerk may not yet have enough driving experience to safely navigate to the offsite location","The vehicle may consume too much fuel traveling between the primary site and the offsite storage facility","The tapes might be exposed to direct sunlight through the vehicle windows during the daytime journey there","Sensitive backup data could be lost, stolen, or accessed in transit due to inadequate physical safeguards"], correct:3, explanation:"Driving experience, fuel, and sunlight are minor; weak physical safeguards in transit risk loss, theft, or unauthorized access to sensitive data." },
  { id:21069, domain:4, level:3, question:"Why might encrypting backups be especially important?", options:["Backup media are portable and stored offsite, so encryption protects the data if media are lost or stolen","Encryption noticeably reduces the physical size of the backup media so that more tapes fit in the cabinet","Encryption makes the backup process run substantially faster than backing up the unencrypted data would","Encryption removes the need to ever test whether the backups can actually be restored later successfully"], correct:0, explanation:"Encryption does not shrink media, speed backups, or remove restore testing; it protects portable, offsite media if lost or stolen." },
  { id:21070, domain:4, level:1, question:"What is RAID primarily used for?", options:["Encrypting individual files before they are transmitted across the organization's wide area network links as a rule","Combining multiple disks to provide redundancy or improved performance, protecting against single disk failure","Scheduling batch jobs to run automatically at predetermined times during the overnight processing windows","Managing the assignment of network IP addresses to the devices connecting to the corporate network daily"], correct:1, explanation:"Encryption, scheduling, and IP assignment are unrelated; RAID combines disks for redundancy and performance against disk failure." },
  { id:21071, domain:4, level:2, question:"Why is RAID not a substitute for backups?", options:["RAID can only be used on servers and never on the desktop workstations used by ordinary office employees","RAID is more expensive than backups, so organizations always prefer to use backups instead of any RAID","RAID protects against disk hardware failure but not against deletion, corruption, ransomware, or site disasters","RAID automatically deletes data after a fixed period, which is exactly why separate backups remain necessary at times"], correct:2, explanation:"RAID is not desktop-limited, cost-driven, or auto-deleting; it guards against disk failure but not deletion, corruption, ransomware, or disasters." },
  { id:21072, domain:4, level:3, question:"An organization relies solely on RAID 5 with no offsite backups. What is the GREATEST resilience gap?", options:["RAID 5 requires slightly more disks than RAID 0, which increases the organization's hardware purchase cost","RAID 5 rebuild times can be lengthy, which only mildly inconveniences the administrators during a disk swap too","RAID 5 uses parity calculations that consume a small amount of additional processor time on the controller","A site-wide disaster or logical corruption could destroy all data because no independent offsite copy exists"], correct:3, explanation:"Disk count, rebuild time, and parity overhead are minor; lacking any offsite copy, a disaster or corruption could destroy all data." },
  { id:21073, domain:4, level:2, question:"Why should backup media be periodically refreshed or migrated to new media?", options:["Storage media degrade over time, so refreshing prevents data loss from aging or obsolete media and drives","Refreshing media is required mainly so the backup team has a recurring task to perform each calendar quarter","Migrating media primarily reduces the data center's electricity bill by replacing the older storage devices","Refreshing backup media is needed chiefly so the media library shelves look neat and well organized"], correct:0, explanation:"Busywork, power, and tidy shelves are not the point; media degrade and become obsolete, so refreshing prevents data loss from aging media." },
  { id:21074, domain:4, level:1, question:"What is the primary purpose of a business continuity plan (BCP)?", options:["Documenting the marketing campaigns the organization intends to launch over the next full fiscal year","Ensuring that critical business functions can continue or be quickly resumed during and after a disruption","Listing the retail prices of all the products the organization currently sells to its external customers in turn","Recording the seating arrangement of employees within each floor of the corporate headquarters building"], correct:1, explanation:"Marketing, prices, and seating are unrelated; a BCP ensures critical functions continue or resume quickly after disruption." },
  { id:21075, domain:4, level:1, question:"What is the purpose of a business impact analysis (BIA)?", options:["Calculating the annual bonus pool to be distributed among all employees at the very end of the fiscal year each time","Selecting the paint colors to be used when redecorating the offices at the corporate headquarters building","Identifying critical business processes and the operational and financial impact of their disruption over time","Designing the layout of the parking lot serving the organization's main office building location each year"], correct:2, explanation:"Bonuses, paint, and parking are unrelated; a BIA identifies critical processes and the impact of disrupting them over time." },
  { id:21076, domain:4, level:2, question:"How does the BIA support setting recovery objectives?", options:["It determines the salary that should be paid to each member of the disaster recovery planning team","It selects the specific brand of generator to be installed as backup power at the primary data center","It schedules the dates on which routine fire drills will be conducted throughout the calendar year","It identifies which processes are most critical and how quickly they must be restored to limit"], correct:3, explanation:"Salaries, generator brands, and fire drills are not BIA outputs; the BIA ranks process criticality and recovery urgency to set objectives." },
  { id:21077, domain:4, level:2, question:"What does recovery time objective (RTO) represent?", options:["The maximum acceptable length of time a business process can be unavailable before unacceptable consequences occur","The maximum amount of data, measured in time, that an organization can afford to lose during an incident","The total monetary cost of building and fully equipping an alternate disaster recovery site for the business by design","The number of staff members required to operate the recovery site during a formally declared disaster event"], correct:0, explanation:"Data loss in time is RPO, and site cost and staffing differ; RTO is the maximum tolerable downtime for a process before serious harm." },
  { id:21078, domain:4, level:2, question:"What does recovery point objective (RPO) represent?", options:["The maximum acceptable length of time that a business process may remain unavailable during a service outage","The maximum acceptable amount of data loss, expressed as a period of time, measured before a disruption occurs","The total floor area required to house all of the equipment installed at the alternate recovery site location over time","The number of backup tapes that must be retained in offsite storage at any given single point in time"], correct:1, explanation:"Tolerable downtime is RTO, and floor area and tape counts differ; RPO is the maximum tolerable data loss measured as a time window." },
  { id:21079, domain:4, level:3, question:"A process has an RPO of one hour. What does this imply about backup frequency?", options:["Backups need only be performed once each day because the recovery point objective is unrelated to backups","Backups must be performed continuously every single second to satisfy the one-hour recovery point objective","Backups or replication must occur at least every hour so that no more than one hour of data is ever lost","Backups should be performed once per week, since an hourly objective refers only to the restoration speed"], correct:2, explanation:"Daily or weekly backups cannot meet a one-hour RPO and per-second is excessive; data must be captured at least hourly to limit loss to one hour." },
  { id:21080, domain:4, level:3, question:"An organization sets aggressive RTOs but allocates minimal recovery budget. What should the IS auditor MOST likely identify?", options:["An exemplary practice because shorter recovery time objectives are always preferable regardless of their cost","A reason to remove the recovery time objectives entirely since they evidently cannot be funded adequately now","Proof that the organization no longer requires any business continuity plan or recovery capability at all","A misalignment between the recovery expectations and the resources required to realistically achieve them"], correct:3, explanation:"Aggressive RTOs are not free, removing objectives or the BCP is wrong; the issue is a mismatch between recovery goals and funding to meet them." },
  { id:21081, domain:4, level:2, question:"Why should the BIA be reviewed and updated periodically?", options:["Business processes, dependencies, and their criticality change over time, so outdated analysis misleads planning","The BIA document tends to fade physically and become unreadable if it is not reprinted on fresh new paper","Regulators require that the BIA be fully rewritten in a different language each year for compliance purposes for them","Updating the BIA is the only acceptable way to keep the disaster recovery team occupied between the drills"], correct:0, explanation:"Fading paper, language rotation, and busywork are not reasons; changing processes and dependencies make stale BIAs misleading for planning." },
  { id:21082, domain:4, level:1, question:"Who should be primarily responsible for identifying critical business processes during a BIA?", options:["External cleaning contractors who happen to be present in the building outside of normal business hours","Business process owners and management who understand the operational importance and dependencies involved","The newest employees who have just joined the organization and are still completing their onboarding now as a rule","The hardware vendor that originally sold the organization the servers running in its primary data center"], correct:1, explanation:"Cleaners, brand-new hires, and hardware vendors lack the needed insight; business owners and management understand process criticality best." },
  { id:21083, domain:4, level:3, question:"During a BIA, two departments each claim their process is the single most critical. How should this be resolved?", options:["By always selecting whichever department happens to have the larger headcount as the more critical of the two","By declaring both processes equally non-critical so as to avoid any appearance of favoring one department","By using objective impact criteria and enterprise priorities to rank processes rather than departmental opinion alone","By letting the department that complains the most loudly receive the highest criticality ranking automatically at times"], correct:2, explanation:"Headcount, blanket downgrading, and loudness are arbitrary; objective impact criteria aligned to enterprise priorities should drive ranking." },
  { id:21084, domain:4, level:2, question:"What is the relationship between maximum tolerable downtime (MTD) and RTO?", options:["RTO and MTD are completely identical terms that can be used interchangeably without any practical difference","RTO must always be set longer than the MTD in order to give the recovery teams extra time to work comfortably too","MTD applies only to hardware while RTO applies only to software, so the two terms never relate to each other","RTO must be shorter than the MTD so recovery completes before the disruption becomes unacceptable to the business"], correct:3, explanation:"They are not identical, RTO longer than MTD defeats the purpose, and neither is hardware/software specific; RTO must fall within the MTD." },
  { id:21085, domain:4, level:2, question:"Why should senior management sponsor and approve the business continuity program?", options:["Their sponsorship ensures adequate resources, authority, and organizational commitment to make the program effective","Senior management approval is required so the continuity plan can be printed on official letterhead paper","Management sponsorship primarily determines which conference room is reserved for the continuity team meetings as well","Their approval is needed chiefly to lengthen the continuity document so it appears more thorough to auditors"], correct:0, explanation:"Letterhead, room booking, and document length are trivial; management sponsorship provides the resources, authority, and commitment needed." },
  { id:21086, domain:4, level:1, question:"What is the primary purpose of a disaster recovery plan (DRP)?", options:["Designing the corporate logo and the overall visual brand identity used across all marketing materials","Restoring IT systems and infrastructure to operational status following a disruptive disaster event","Scheduling the routine cleaning of the office carpets and windows throughout the headquarters building","Negotiating volume discounts on the office supplies purchased for the various corporate departments"], correct:1, explanation:"Logos, cleaning, and supplies are unrelated; a DRP focuses on restoring IT systems and infrastructure after a disaster." },
  { id:21087, domain:4, level:2, question:"How does a disaster recovery plan relate to a business continuity plan?", options:["The DRP and BCP are completely unrelated documents that no organization should ever cross-reference at all","The BCP is a narrow subset of the DRP that addresses only the recovery of physical office furniture items","The DRP is a component of the broader BCP, focused specifically on recovering IT systems and infrastructure","The DRP replaces the BCP entirely once an organization has finished documenting all of its IT recovery steps"], correct:2, explanation:"They are related, the BCP is broader not narrower, and neither replaces the other; the DRP is the IT-focused part of the wider BCP." },
  { id:21088, domain:4, level:1, question:"What is a hot site in disaster recovery?", options:["An empty facility providing only floor space, power, and cooling but no installed computing equipment at all as noted","A facility shared by multiple organizations that takes several weeks to make operational after a disaster","A storage room used solely to keep backup tapes and other media safe from the primary site's hazards","A fully equipped alternate facility with systems ready to assume operations almost immediately after a disaster"], correct:3, explanation:"An empty shell is a cold site, weeks of readiness suggests cold, and a media room is storage; a hot site is fully equipped and near-immediate." },
  { id:21089, domain:4, level:1, question:"What is a cold site in disaster recovery?", options:["A facility providing space, power, and cooling but lacking installed systems, requiring setup before any use","A fully operational facility with live, continuously updated systems ready to take over operations instantly","A mobile trailer that is driven to the disaster location and made operational within just a few short minutes","A secure vault that is used only for storing encrypted backup media away from the primary data center"], correct:0, explanation:"Fully operational describes a hot site, a mobile unit differs, and a vault is storage; a cold site has space and utilities but no installed systems." },
  { id:21090, domain:4, level:2, question:"What characterizes a warm site compared with hot and cold sites?", options:["It is identical to a hot site in every single respect but is simply located in a much warmer geographic climate","It is partially equipped with some hardware and connectivity, requiring moderate effort and time to activate","It is identical to a cold site in every single respect but is simply located in a much warmer geographic climate","It is a facility that can never actually be used for recovery and exists only for periodic disaster testing"], correct:1, explanation:"Climate is irrelevant and a warm site is usable; it sits between hot and cold, partially equipped and needing moderate activation effort." },
  { id:21091, domain:4, level:3, question:"An organization needs an RTO of two hours for a critical system. Which recovery strategy is MOST appropriate?", options:["A cold site, because its lower overall cost makes it the best choice regardless of the recovery time objective","Offsite tape storage with a manual rebuild, since restoring from tape is always faster than using any site","A hot site with replicated data, because cold or warm sites cannot realistically be activated within two hours","No alternate site at all, because two hours is more than enough time to fully repair the original primary site"], correct:2, explanation:"Cold sites and tape rebuilds take far longer than two hours and repair is not guaranteed; a hot site with replication meets a two-hour RTO." },
  { id:21092, domain:4, level:3, question:"Why might a reciprocal agreement with another organization be a risky recovery strategy?", options:["Reciprocal agreements are always far more expensive than building and maintaining a dedicated hot site","Reciprocal agreements require both organizations to use exactly the same brand of office furniture","Reciprocal agreements are strictly prohibited by law in virtually every jurisdiction around the world today in practice","The partner's resources may be insufficient or unavailable, especially if a regional disaster affects both parties"], correct:3, explanation:"Reciprocal deals are typically cheaper, furniture is irrelevant, and they are not illegal; the risk is the partner's capacity may be inadequate or shared." },
  { id:21093, domain:4, level:2, question:"Why is a documented call tree or notification procedure important in a DRP?", options:["It ensures the right people are contacted quickly and in the correct order to mobilize the recovery effort","It records the personal social media usernames of every employee for the marketing outreach campaigns for them","It lists the home addresses of all staff so that the company holiday cards can be mailed each year","It tracks how many vacation days each member of the recovery team has accrued during the current year"], correct:0, explanation:"Social media, holiday cards, and vacation tracking are unrelated; a call tree ensures rapid, ordered notification to mobilize recovery." },
  { id:21094, domain:4, level:2, question:"An IS auditor finds the DRP lists recovery steps but never specifies who performs each one. What is the MAIN weakness?", options:["The plan document will require slightly more pages once the responsible individuals are finally added to it","Without assigned roles and responsibilities, confusion and delay are likely when the plan must be executed","The plan cannot be printed in full color until every step has a single named owner assigned to perform it","The plan will be far too short to satisfy the page-count expectations of any external regulatory bodies"], correct:1, explanation:"Page count and printing are trivial; unassigned responsibilities cause confusion and delay precisely when the plan must work." },
  { id:21095, domain:4, level:3, question:"Why should a DRP account for dependencies on third-party service providers?", options:["Third-party providers always recover much faster than the organization, so listing them is purely a formality","Documenting providers is required only so the organization can compare their prices during contract renewal","A provider's own outage or failure to recover could prevent the organization from restoring its own services","Providers must be listed in the DRP solely to satisfy the marketing department's annual vendor showcase page"], correct:2, explanation:"Providers do not always recover faster, and pricing or marketing are not the point; their own outages can block the organization's recovery." },
  { id:21096, domain:4, level:2, question:"What is the purpose of maintaining current network and system documentation for disaster recovery?", options:["Documentation is needed mainly so the organization can win industry awards for its thorough record keeping","Documentation exists primarily to give new auditors something lengthy to read during their very first week","Documentation is required only to justify the salaries of the technical writing staff who actually produce it as well","Accurate documentation enables responders to rebuild and reconfigure systems correctly and quickly during recovery"], correct:3, explanation:"Awards, auditor reading, and justifying salaries are not the purpose; accurate documentation lets responders rebuild systems correctly and fast." },
  { id:21097, domain:4, level:1, question:"What is data replication in the context of resilience?", options:["Copying data to a secondary location in near real time so an up-to-date copy is available for recovery","Permanently deleting duplicate files to reclaim valuable storage space across the organization's disk arrays","Compressing data so that it occupies much less space on the primary production storage system over time","Renaming files according to a standard convention so that they are far easier for users to locate later"], correct:0, explanation:"Replication is not deletion, compression, or renaming; it copies data to a secondary location, often in near real time, for recovery." },
  { id:21098, domain:4, level:3, question:"How does synchronous replication differ from asynchronous replication in terms of recovery?", options:["Synchronous and asynchronous replication are entirely identical and the two terms are used purely interchangeably too","Synchronous confirms writes at both sites before completing, minimizing data loss but adding latency over distance","Synchronous replication copies data only once per week, while asynchronous copies the data continuously all day","Asynchronous replication guarantees zero data loss, while synchronous always loses several hours of recent data"], correct:1, explanation:"They are not identical or weekly, and asynchronous, not synchronous, can lose data; synchronous confirms both sites first, reducing loss but adding latency." },
  { id:21099, domain:4, level:2, question:"Why is geographic separation between primary and recovery sites important?", options:["Greater distance between the two sites noticeably reduces the monthly electricity bill at the primary center","Separating the sites geographically makes the network connection between the two of them noticeably faster","A regional event such as a flood or earthquake is less likely to disable both sites if they are far apart","More distant recovery sites are fully exempt from the data protection regulations that apply to the primary site"], correct:2, explanation:"Distance does not cut power bills, speed networks, or grant regulatory exemptions; separation reduces the chance one regional event disables both." },
  { id:21100, domain:4, level:3, question:"An organization's recovery site is in the same flood plain as its primary site. What is the PRIMARY concern?", options:["The two sites being close together will simply make it cheaper to lease network connectivity between them","Staff will find it far more convenient to travel between two sites that are located close to one another","Both sites can share the same physical security guards, slightly reducing the organization's overall staffing cost","A single regional flood could simultaneously disable both the primary and recovery sites, defeating the strategy"], correct:3, explanation:"Cheaper links, convenience, and shared guards are minor or counterproductive; co-located in one flood plain means one event can disable both." },
  { id:21101, domain:4, level:1, question:"What is high availability in IT systems?", options:["A design approach that minimizes downtime by using redundant components to keep services continuously operational","A method of compressing data so that it occupies the least possible space on the storage subsystem available by design","A scheduling technique that runs all of the batch jobs at the highest possible processor priority setting","A pricing model under which software is licensed based on the number of concurrent users that it supports"], correct:0, explanation:"Compression, scheduling priority, and licensing are unrelated; high availability uses redundancy to minimize downtime and keep services running." },
  { id:21102, domain:4, level:2, question:"How does clustering improve availability?", options:["Clustering increases the clock speed of each individual processor in every single server within the group","Multiple servers work together so that if one node fails, another takes over the workload with minimal disruption","Clustering encrypts all of the data exchanged between the servers to protect it from network eavesdroppers","Clustering reduces the physical size of the servers so that many more of them fit into a single equipment rack over time"], correct:1, explanation:"Clustering does not raise clock speed, encrypt traffic, or shrink servers; it lets surviving nodes take over when one fails, sustaining availability." },
  { id:21103, domain:4, level:1, question:"What is fault tolerance?", options:["The maximum number of user errors a help desk is permitted to tolerate before escalating a given ticket","The degree to which an organization accepts financial losses from operational disruptions each fiscal year","The ability of a system to continue operating correctly even when one or more of its components fail","The temperature range within which a data center's cooling equipment is specifically designed to operate"], correct:2, explanation:"It is not about help-desk errors, financial risk appetite, or cooling ranges; fault tolerance is continued correct operation despite component failure." },
  { id:21104, domain:4, level:2, question:"What is the purpose of a redundant power supply in a server?", options:["It doubles the processing speed of the server by supplying additional electrical current to the main processor","It allows the server to operate entirely without any connection to the building's main electrical power source","It reduces the amount of heat that the server generates, thereby lowering the data center's cooling requirements","If one power supply unit fails, the second continues delivering power so the server stays fully operational"], correct:3, explanation:"It does not boost speed, eliminate mains power, or cut heat; a redundant supply keeps the server running if the other power unit fails." },
  { id:21105, domain:4, level:3, question:"An organization clusters its application servers but connects them all to a single network switch. What resilience flaw exists?", options:["The single switch is a single point of failure whose loss would disconnect the entire cluster all at once","Clustering automatically requires at least three switches, so using just one violates the clustering license terms","A single network switch cannot physically support more than two servers connected to it at the same time","Clustered servers must each use a different brand of switch or the cluster will simply refuse to form properly"], correct:0, explanation:"License terms, port limits, and brand mixing are fabricated; the real flaw is that the lone switch is a single point of failure for the whole cluster." },
  { id:21106, domain:4, level:2, question:"What is a single point of failure (SPOF)?", options:["A server that has been configured to fail deliberately during a scheduled disaster recovery testing exercise","A component whose failure alone would cause an entire system or service to become completely unavailable","A network port that is reserved exclusively for use by the organization's most senior executive officer","A backup copy that is stored at one single location rather than being duplicated across multiple sites"], correct:1, explanation:"It is not a deliberate failure, a reserved port, or a backup copy; a SPOF is any component whose failure brings down the whole service." },
  { id:21107, domain:4, level:3, question:"Why does adding redundancy not automatically guarantee high availability?", options:["Redundancy always reduces availability because more components simply mean more parts that can possibly break","Redundancy guarantees availability only if every redundant component is supplied by a completely different vendor too","Redundant components must be properly configured, monitored, and tested so that failover actually works when needed","Redundancy is purely a financial concept and has no actual effect on whether systems remain available at all"], correct:2, explanation:"Redundancy is not inherently harmful, vendor diversity is not required, and it does affect availability; it must be configured, monitored, and tested." },
  { id:21108, domain:4, level:2, question:"What is load balancing primarily used for?", options:["Encrypting the data stored on each server's local disk to protect it against any unauthorized access attempts","Scheduling overnight batch jobs to run in a sequence that properly respects their processing dependencies","Compressing files before they are transmitted across the wide area network between the various branch offices","Distributing workload across multiple servers to improve performance and avoid overloading any single server"], correct:3, explanation:"Encryption, scheduling, and compression are unrelated; load balancing spreads workload across servers to improve performance and avoid overload." },
  { id:21109, domain:4, level:3, question:"How can load balancing contribute to availability as well as performance?", options:["If one server fails, the load balancer can route incoming traffic to the remaining healthy servers automatically","Load balancing prevents servers from ever failing by reducing the electrical load that is placed upon each one as well","Load balancing makes a single server powerful enough that no additional servers are ever needed at any point","Load balancing encrypts traffic so thoroughly that attackers can never cause any of the servers to fail at all"], correct:0, explanation:"It does not prevent failures, replace extra servers, or rely on encryption; it can reroute traffic away from a failed server, aiding availability." },
  { id:21110, domain:4, level:2, question:"What is the purpose of an uninterruptible power supply (UPS) in a data center?", options:["Permanently powering the entire data center indefinitely without any need for grid or generator power at all","Providing short-term battery power during an outage so systems stay running until backup generators start","Cooling the servers by circulating chilled air through the racks during the periods of highest utilization","Filtering all malicious network traffic before it can reach the servers housed within the data center"], correct:1, explanation:"A UPS does not run indefinitely, cool servers, or filter traffic; it provides bridging battery power until generators take over." },
  { id:21111, domain:4, level:2, question:"Why should failover mechanisms be tested rather than assumed to work?", options:["Testing failover is required mainly so the operations team can document additional procedures in the runbook","Failover testing primarily determines the resale value of the redundant hardware when it is later decommissioned","Untested failover may fail to activate during a real outage, leaving the supposedly redundant system unavailable","Testing failover exists chiefly to keep the infrastructure team occupied during otherwise quiet weekend shifts"], correct:2, explanation:"Documentation, resale value, and busywork are not the point; untested failover may not activate in a real outage, defeating redundancy." },
  { id:21112, domain:4, level:1, question:"What is a primary responsibility of a database administrator (DBA)?", options:["Designing the printed marketing brochures used to promote the organization's products to new customers","Approving employee travel expense reports submitted within the finance department at the end of each month","Installing physical network cabling between the workstations and the floor wiring closets on every level","Managing database performance, integrity, availability, and security across the organization's databases"], correct:3, explanation:"Brochures, expense approval, and cabling are unrelated; the DBA manages database performance, integrity, availability, and security." },
  { id:21113, domain:4, level:2, question:"Why is separating DBA duties from application development an important control?", options:["It reduces the risk that one person could both make unauthorized data changes and conceal them from detection","It ensures that database administrators will always earn a much higher salary than the application developers","It guarantees that the database will never experience any performance problems during the peak usage hours","It allows the organization to purchase noticeably fewer software licenses for its database management system"], correct:0, explanation:"Salary, performance, and licensing are irrelevant; separating duties prevents one person from both altering data and hiding it." },
  { id:21114, domain:4, level:3, question:"An IS auditor finds DBAs use a single shared admin account for all database changes. What is the PRIMARY concern?", options:["The shared account name is simply too short and may be easy for outsiders to guess during an active attack","Individual actions cannot be attributed to specific people, undermining accountability and forensic investigation","Using one shared account means the database vendor will charge a higher fee for its annual support contract over time","A shared account causes the database to run noticeably more slowly because many people log in using it"], correct:1, explanation:"Name length, support cost, and speed are not the issue; a shared account prevents attributing actions to individuals, undermining accountability." },
  { id:21115, domain:4, level:2, question:"Why should database transaction logs be protected and retained?", options:["They are the primary means of calculating how much electrical power the database server actually consumes","They determine the font and the color scheme used when the database displays its query results to users","They support recovery to a point in time and provide an audit trail of changes for later investigation","They control the physical temperature that is maintained inside the cabinet housing the database server"], correct:2, explanation:"Power, fonts, and temperature are unrelated; transaction logs enable point-in-time recovery and provide an audit trail of changes." },
  { id:21116, domain:4, level:1, question:"What is the role of network operations in IT?", options:["Writing the source code for the organization's customer-facing mobile and web application products","Conducting performance appraisals for all employees working within the human resources department","Designing the printed packaging used for the physical products the organization sells to its customers in practice","Monitoring and maintaining the network infrastructure to ensure reliable connectivity and performance for users"], correct:3, explanation:"Coding, HR appraisals, and packaging are unrelated; network operations monitors and maintains the network for reliable connectivity." },
  { id:21117, domain:4, level:2, question:"Why is network performance monitoring important for operations?", options:["It detects congestion, faults, and degradation early so issues can be addressed before users are seriously affected","It calculates the eventual resale value of the network switches when they are eventually decommissioned and sold too","It determines which employees are permitted to bring their own personal devices into the office building","It schedules the specific dates on which the network team will take their annual vacation leave each year"], correct:0, explanation:"Resale value, device policy, and vacations are unrelated; monitoring detects congestion and faults early so they can be addressed proactively." },
  { id:21118, domain:4, level:3, question:"An organization's network team reacts to outages only after users complain. What operational weakness does this indicate?", options:["The network team is simply too large and should be reduced because the users are doing the monitoring for them","The absence of proactive monitoring means problems are detected late, increasing downtime and overall business impact","The organization is saving money very effectively by avoiding the cost of any network monitoring tools at all","The practice is ideal because user complaints are always far more accurate than any automated monitoring alerts at times"], correct:1, explanation:"A larger team, false savings, and trusting complaints are wrong; lacking proactive monitoring means late detection, more downtime, and impact." },
  { id:21119, domain:4, level:2, question:"Why should administrative access to network devices be tightly controlled and logged?", options:["Logging administrative access is the primary method used to measure each device's daily electrical consumption","Restricting the access ensures that the network devices will physically last much longer before needing replacement","Unauthorized configuration changes could disrupt connectivity or weaken security across the entire network","Controlling the access determines the color of the status lights displayed on the front of each device"], correct:2, explanation:"Power measurement, hardware lifespan, and light color are irrelevant; tight control and logging prevent disruptive or insecure configuration changes." },
  { id:21120, domain:4, level:3, question:"How should an IS auditor verify that only authorized changes were made to firewall rules?", options:["By confirming that the firewall hardware is the very newest model currently offered by the manufacturer","By counting the total number of rules configured and ensuring the count remains below a fixed upper limit","By verifying that the firewall is painted the same color as all of the other devices in the equipment rack each time","By comparing the current firewall configuration against approved change records and investigating any discrepancies"], correct:3, explanation:"Hardware model, rule count, and color are not evidence; comparing the live configuration to approved changes and probing discrepancies verifies authorization." },
  { id:21121, domain:4, level:2, question:"What is the purpose of a system hardening standard in operations?", options:["Defining secure baseline configurations that reduce vulnerabilities by disabling unnecessary services and features","Specifying the maximum physical weight that a server is permitted to have before its installation in a rack as well","Determining the precise order in which the servers should be powered on after a planned maintenance window","Setting the brightness of the indicator lights on the front panel of each server inside the data center"], correct:0, explanation:"Weight, power-on order, and light brightness are irrelevant; a hardening standard defines secure baselines that reduce vulnerabilities." },
  { id:21122, domain:4, level:2, question:"Why is monitoring database performance metrics important in operations?", options:["Database performance metrics are collected mainly to calculate the resale value of the database server hardware","Degrading query performance can signal capacity, indexing, or contention issues before they cause an outage","Monitoring performance primarily determines which database administrator is assigned the largest office desk","Performance metrics exist chiefly so the database team has additional numbers to include in status reports"], correct:1, explanation:"Resale value, desks, and report padding are irrelevant; performance metrics reveal capacity and contention issues before they cause outages." },
  { id:21123, domain:4, level:1, question:"What does data lifecycle management address?", options:["How the organization decorates its data center to make it appear more visually appealing to visiting clients","How employees are assigned parking spaces near the building based on their seniority within the company","How data is created, stored, used, archived, and ultimately disposed of throughout its useful existence","How the organization selects which charities to support through its annual corporate giving program"], correct:2, explanation:"Decoration, parking, and charity are unrelated; data lifecycle management covers data from creation through use, archival, and disposal." },
  { id:21124, domain:4, level:2, question:"Why is a data retention policy important from a compliance perspective?", options:["It guarantees that the organization will never run out of physical disk storage capacity at any point","It determines the speed at which users can retrieve archived records from the long-term storage system","It sets the specific brand of storage hardware the organization is required to purchase for its archives as noted","It ensures data is kept as long as legally required and disposed of when retention is no longer justified"], correct:3, explanation:"Unlimited storage, retrieval speed, and hardware brand are not the point; a retention policy keeps data as long as required and disposes appropriately." },
  { id:21125, domain:4, level:3, question:"An organization retains all data indefinitely to be safe. What risk does this MOST likely create?", options:["Excessive retention increases storage cost, breach exposure, and potential legal liability for outdated records","Indefinite retention is always the safest possible approach and creates no meaningful risk for the organization","Keeping the data forever guarantees that the organization will never face any regulatory penalties whatsoever","Indefinite retention automatically improves the performance of every application that accesses the stored data"], correct:0, explanation:"Indefinite retention is not risk-free or performance-improving; it raises storage cost, breach exposure, and legal liability for stale data." },
  { id:21126, domain:4, level:2, question:"Why is secure data disposal important when decommissioning storage media?", options:["Disposing of the media securely makes the storage devices physically lighter and far easier to carry out","Residual data could be recovered from improperly wiped media, exposing sensitive information to unauthorized parties","Secure disposal is required mainly so the organization can claim a larger tax deduction for the equipment","Proper disposal ensures the replacement media will operate noticeably faster than the equipment being discarded up front"], correct:1, explanation:"Weight, tax deductions, and replacement speed are irrelevant; improperly wiped media can leak recoverable sensitive data to unauthorized parties." },
  { id:21127, domain:4, level:3, question:"Which method provides the STRONGEST assurance that data on decommissioned drives cannot be recovered?", options:["Deleting the files through the operating system and then emptying the desktop recycle bin afterward completely up front","Renaming all of the files to meaningless names so that nobody can identify their actual contents later on","Physical destruction or certified degaussing of the media, eliminating the possibility of any later data recovery","Moving the files into a hidden folder that ordinary users are very unlikely to think to look inside"], correct:2, explanation:"Deletion, renaming, and hiding leave data recoverable; physical destruction or certified degaussing reliably prevents recovery." },
  { id:21128, domain:4, level:2, question:"An IS auditor finds decommissioned laptops are donated to charity without any data wiping. What is the PRIMARY concern?", options:["The charity may prefer a different brand of laptop than the particular model the organization donated to them for them","The laptops may have slightly worn keyboards that make them somewhat less pleasant for recipients to use","Donating the laptops may reduce the organization's available stock of spare parts for future repairs","Sensitive organizational data remaining on the drives could be exposed to the recipients of the donated laptops"], correct:3, explanation:"Brand preference, worn keys, and spare parts are trivial; unwiped drives can expose sensitive organizational data to laptop recipients." },
  { id:21129, domain:4, level:2, question:"Why should data classification inform retention and disposal decisions?", options:["Different classes of data carry different legal, regulatory, and sensitivity requirements affecting how they","Data classification determines the physical color of the folders in which the paper records are then filed","Classifying data is required only so the IT department appears busier during the annual external audit period","Classification sets the order in which the servers are rebooted following a scheduled maintenance window"], correct:0, explanation:"Folder color, appearances, and reboot order are irrelevant; classification reflects differing legal and sensitivity requirements that drive handling." },
  { id:21130, domain:4, level:1, question:"What is asset management in IT operations?", options:["Managing the organization's stock market investments and financial securities portfolio every calendar quarter","Tracking IT hardware and software assets throughout their lifecycle from acquisition through to disposal","Scheduling the cleaning of the office spaces and common areas within the corporate headquarters building","Designing the user interface for the organization's customer-facing online shopping application product"], correct:1, explanation:"Investments, cleaning, and UI design are unrelated; IT asset management tracks hardware and software across their lifecycle." },
  { id:21131, domain:4, level:2, question:"Why is an accurate IT asset inventory important for resilience and security?", options:["An asset inventory is needed mainly to calculate the total physical weight of all equipment in the data center","Maintaining an inventory primarily determines the order in which the assets are arranged on the storage shelves","You cannot protect, patch, or recover assets you are not aware of, so unknown assets create serious blind spots","An accurate inventory exists chiefly to give the audit team a long document to review during their fieldwork"], correct:2, explanation:"Weight, shelf order, and audit reading are not the point; unknown assets cannot be protected, patched, or recovered, creating blind spots." },
  { id:21132, domain:4, level:3, question:"An IS auditor finds the asset inventory omits many virtual servers created on demand. What is the PRIMARY risk?", options:["The inventory document will simply be slightly shorter than expected because some entries are not included","Virtual servers consume less electricity than physical ones, so omitting them understates the total power bill","The omission means the organization owns fewer software licenses than it actually needs to purchase overall","Untracked virtual servers may go unpatched and unmonitored, expanding the attack surface and the recovery gaps"], correct:3, explanation:"Document length, power, and license counts are minor or unrelated; untracked virtual servers may be unpatched and unmonitored, widening exposure." },
  { id:21133, domain:4, level:2, question:"Why should configuration baselines be established and monitored for drift?", options:["Unauthorized or unintended configuration changes can introduce vulnerabilities or instability if left undetected","Configuration baselines are needed mainly to determine the color scheme of the administrative dashboards","Monitoring for drift primarily measures how much electricity each individually configured server consumes daily as well","Baselines exist chiefly so that the configuration team has additional documents to file every single quarter"], correct:0, explanation:"Dashboard color, power, and filing are irrelevant; baselines and drift detection catch unauthorized changes that cause vulnerabilities or instability." },
  { id:21134, domain:4, level:1, question:"What is incident escalation?", options:["Deliberately increasing the severity rating of every incident so that the support team appears much busier","Routing an incident to higher support tiers or management when it cannot be resolved at the current level","Deleting an incident record once it has remained open for longer than a single full business day already","Forwarding an incident to the marketing department so it can be featured in the next customer newsletter"], correct:1, explanation:"Inflating severity, deleting records, and forwarding to marketing are wrong; escalation routes unresolved incidents to higher tiers or management." },
  { id:21135, domain:4, level:2, question:"Why should incidents be categorized and prioritized?", options:["Categorizing incidents is required mainly to make the printed incident report document appear more colorful","Prioritization primarily determines which of the support staff are entitled to take their lunch break first","Categorization and prioritization ensure the most critical incidents receive attention and resources first","Categorizing incidents exists chiefly to increase the total number of fields in the ticketing system records"], correct:2, explanation:"Report color, lunch order, and field counts are irrelevant; categorization and prioritization ensure critical incidents get attention and resources first." },
  { id:21136, domain:4, level:3, question:"An organization closes incidents quickly but the same issues keep recurring. Which process is MOST likely deficient?", options:["Capacity management, since recurring incidents are always caused by insufficient processing resources alone","Change management, because closing incidents quickly necessarily means that too many changes are occurring","Asset management, as the recurrence clearly indicates that the asset inventory is missing many key entries","Problem management, which should identify and remediate the root causes behind the recurring incidents"], correct:3, explanation:"Capacity, change, and asset management are not implicated by recurrence alone; quick closure with recurrence points to weak problem management." },
  { id:21137, domain:4, level:2, question:"What is the purpose of a post-incident review (lessons learned)?", options:["Analyzing what happened and why to prevent recurrence and improve future incident response and resilience","Assigning blame to a specific individual so that disciplinary action can be taken against them very quickly","Calculating how much overtime pay the response team earned while resolving the incident that occurred","Producing a lengthy report whose main purpose is to demonstrate that the team was kept fully occupied"], correct:0, explanation:"Blame, overtime, and busywork are not the goal; a post-incident review analyzes cause to prevent recurrence and improve response." },
  { id:21138, domain:4, level:2, question:"Why is monitoring storage capacity utilization important in operations?", options:["Monitoring storage utilization is needed mainly to calculate the total physical weight of the disk arrays","Running out of storage can halt processing, prevent backups, and cause application failures if not anticipated","Storage monitoring primarily determines the color of the warning lights placed on the storage cabinet doors over time","Tracking utilization exists chiefly so the storage team has many more numbers to include in status reports"], correct:1, explanation:"Weight, light color, and report padding are irrelevant; unanticipated storage exhaustion can halt processing, block backups, and crash applications." },
  { id:21139, domain:4, level:3, question:"An IS auditor reviews resilience controls and finds backups, redundancy, and a DR plan exist but are never tested together. What is the BEST conclusion?", options:["The mere presence of the controls alone fully guarantees that any disaster will be recovered from successfully","Testing the controls together is unnecessary because each control was tested individually at the time of purchase","Individual controls existing without integrated testing provide limited assurance that recovery will succeed end","The controls should be removed since untested controls evidently provide no value of any kind to the organization"], correct:2, explanation:"Existence alone does not guarantee recovery, and removing controls is extreme; without integrated testing, end-to-end recovery assurance is limited." },
  { id:21140, domain:4, level:2, question:"Why should operational procedures be formally documented rather than relying on staff knowledge?", options:["Documenting procedures is required mainly so the operations binder is thick enough to look genuinely impressive","Written procedures primarily determine which staff members are assigned the largest desks in the open office","Documentation exists chiefly so that auditors have a lengthy set of papers to read during their fieldwork","Documented procedures ensure consistency and continuity even when experienced staff are unavailable or leave"], correct:3, explanation:"A thick binder, desk assignments, and auditor reading are not the point; documentation ensures consistency and continuity when staff are unavailable." },
  { id:21141, domain:4, level:1, question:"What is the purpose of access reviews for privileged operations accounts?", options:["Periodically confirming that privileged access remains appropriate and removing rights that are no longer needed","Increasing the number of privileged accounts so that more staff can perform administrative tasks more quickly for them","Determining which administrators are entitled to the most powerful workstations within the operations area","Calculating the total electrical consumption attributable to all privileged users across the data center"], correct:0, explanation:"Adding accounts, workstation perks, and power use are wrong; access reviews confirm privileged access is still appropriate and revoke unneeded rights." },
  { id:21142, domain:4, level:3, question:"An organization grants temporary elevated access for an emergency but never revokes it afterward. What is the PRIMARY concern?", options:["The temporary access may have been granted using a slightly outdated version of the formal access request form as a rule","Lingering excessive privileges increase the risk of misuse or compromise long after the emergency has fully ended","The elevated access could cause the administrator's workstation to run somewhat more slowly than it did before","Retaining the access means the organization must keep one additional row in its access tracking spreadsheet"], correct:1, explanation:"Form versions, workstation speed, and spreadsheet rows are trivial; unrevoked elevated access leaves excessive privileges that can be misused." },
  { id:21143, domain:4, level:2, question:"Why is it important to align IT resilience capabilities with business recovery requirements?", options:["Aligning capabilities with the business is required mainly so the IT department merely appears cooperative in meetings","The alignment primarily determines which business unit will receive the newest office furniture each fiscal year","Resilience spending should match the criticality and recovery needs of the business to avoid over- or under-protection","Matching capabilities to requirements exists chiefly to lengthen the IT strategy document presented to the board"], correct:2, explanation:"Appearances, furniture, and document length are irrelevant; aligning resilience to business criticality avoids both over- and under-protection." },
  { id:21144, domain:4, level:1, question:"What is the primary purpose of testing a disaster recovery plan?", options:["Providing the recovery team with an enjoyable social activity intended to improve overall team morale","Satisfying a requirement to use the alternate recovery site so that its annual lease cost can be justified","Generating documentation that can be proudly displayed to visitors touring the data center facility","Validating that the plan actually works and identifying any gaps in it before a real disaster ever occurs"], correct:3, explanation:"Morale, justifying leases, and visitor displays are not the purpose; DR testing validates the plan and surfaces gaps before a real disaster." },
  { id:21145, domain:4, level:1, question:"What is a tabletop (walkthrough) test of a recovery plan?", options:["A discussion-based exercise where team members review and talk through their roles and the plan's steps","A full activation of the recovery site with all of the production systems failed over to it for a whole day","An automated test in which software executes the entire recovery procedure without any human involvement","A physical inspection of the data center's fire suppression and cooling systems by an external safety inspector"], correct:0, explanation:"Full failover, automated execution, and physical inspection are different; a tabletop test is a discussion-based walkthrough of roles and steps." },
  { id:21146, domain:4, level:2, question:"How does a full interruption (full-scale) DR test differ from a parallel test?", options:["A full interruption is always shorter in total duration than a parallel test and involves far fewer staff members","A full interruption shifts live operations to the recovery site, while a parallel test runs recovery alongside","A parallel test shuts down production entirely, while a full interruption leaves production running undisturbed","There is no meaningful difference at all; the two terms describe exactly the same disaster recovery testing activity"], correct:1, explanation:"The descriptions are not reversed, equal, or identical; full interruption moves live operations to recovery, while parallel runs recovery beside production." },
  { id:21147, domain:4, level:3, question:"Why is a full interruption test riskier than other DR test types?", options:["It requires the most paperwork to be completed, which only slightly delays the start of the testing activity each time","It is the only test type that involves the active participation of the organization's recovery team members","It actually transfers live operations to the recovery site, so a failure could disrupt real business processing","It must always be scheduled on a weekend, which is somewhat inconvenient for the staff involved in the test"], correct:2, explanation:"Paperwork, team involvement, and scheduling are minor; full interruption moves live operations, so a failure can disrupt actual business processing." },
  { id:21148, domain:4, level:2, question:"Why should DR test results be documented and reviewed?", options:["Documentation is required mainly so the recovery team has something lengthy to file away in long-term storage","Reviewing results is the only acceptable way to keep the recovery team genuinely occupied between actual disasters","Documented results are needed primarily to calculate the electricity used by the recovery site during the test","Documented results reveal gaps and lessons that drive improvements to the plan before a real event ever occurs"], correct:3, explanation:"Busywork, occupying staff, and power calculations are not the point; documenting results exposes gaps and lessons that improve the plan." },
  { id:21149, domain:4, level:3, question:"A DR test succeeds but takes twice the target RTO to recover systems. What should the IS auditor conclude?", options:["The plan is not yet adequate because recovery exceeds the objective, and improvements are needed to meet the RTO","The test is a complete success because the systems were eventually recovered regardless of how long it actually took","The recovery time objective should simply be doubled so that the existing test result now appears to fully pass","The result is irrelevant because recovery time has no real bearing on whether a disaster recovery plan is effective"], correct:0, explanation:"Eventual recovery, redefining the RTO, and dismissing time are wrong; exceeding the RTO means the plan is inadequate and must be improved." },
  { id:21150, domain:4, level:2, question:"Why should DR tests be conducted periodically rather than only once?", options:["Repeated testing is required mainly so the recovery team can accumulate enough overtime pay during each year over time","Systems, configurations, and dependencies change over time, so a plan validated once may fail when later needed","Periodic testing is the only way to physically prevent the recovery site's equipment from gradually aging","Conducting the tests repeatedly increases the eventual resale value of the equipment at the recovery site"], correct:1, explanation:"Overtime pay, preventing aging, and resale value are irrelevant; environments change, so a once-validated plan may fail unless retested periodically." },
  { id:21151, domain:4, level:3, question:"An IS auditor notes DR tests are always scheduled and announced well in advance. What limitation does this introduce?", options:["Announced tests cannot be documented properly because the team already knows the exact test date beforehand","Scheduling tests in advance violates regulations that require all DR testing to be completely spontaneous","Announced tests may not reflect the unpredictability of a real disaster, potentially overstating the actual readiness","Pre-announced tests are unable to involve the recovery site and so must be conducted at the primary site only up front"], correct:2, explanation:"Documentation, regulations, and site limits are not the issue; announced tests can overstate readiness because real disasters are unpredictable." },
  { id:21152, domain:4, level:2, question:"What is the value of involving business users in disaster recovery testing?", options:["They provide extra people to help carry the equipment between the primary and recovery sites during the test in practice","Their presence is required only so that the catering budget for the test day can be more easily justified","They are needed primarily to take photographs of the recovery site for the company's internal newsletter","They can confirm that the recovered systems actually support real business processes and meet operational needs"], correct:3, explanation:"Carrying equipment, catering, and photos are trivial; business users confirm that recovered systems truly support real business processes." },
  { id:21153, domain:4, level:3, question:"Why might a parallel DR test be preferred over a full interruption test for an initial validation?", options:["It exercises recovery systems without disrupting production, reducing risk while still validating recovery capability","It is the only test type that produces any documentation, so it is always preferred for the very first test","A parallel test guarantees zero data loss, whereas a full interruption test always loses several hours of data for them","Parallel tests require no participation from technical staff, making them cheaper and far easier to coordinate"], correct:0, explanation:"Documentation, guaranteed zero loss, and no staff are wrong; a parallel test validates recovery without disrupting production, lowering initial risk." },
  { id:21154, domain:4, level:2, question:"What is the shared responsibility model in cloud operations?", options:["The cloud provider assumes complete responsibility for every single aspect of security, leaving the customer none at all","The cloud provider and customer each hold defined security and operational responsibilities depending on the service","The customer is solely responsible for absolutely everything, and the provider merely supplies bare physical hardware","Responsibilities are randomly reassigned between the provider and customer at the start of each new calendar month"], correct:1, explanation:"Total provider or customer ownership and random reassignment are wrong; responsibilities are split by service model between provider and customer." },
  { id:21155, domain:4, level:3, question:"An organization assumes its cloud provider automatically backs up all data. What audit concern does this MOST raise?", options:["The cloud provider will likely charge a small additional fee for storing the customer's various backup data sets","The customer's data may load slightly more slowly because cloud backups happen to run during business hours","The customer may have responsibilities for backup that it has not fulfilled, risking unrecoverable data loss","The provider may use a different brand of storage hardware than the customer would have otherwise chosen"], correct:2, explanation:"Fees, load speed, and hardware brand are minor; assuming provider backup without confirming responsibilities risks unrecoverable data loss." },
  { id:21156, domain:4, level:2, question:"Why is reviewing a cloud provider's resilience and SLA commitments important?", options:["Reviewing the provider's SLA is required mainly so the customer can compare the provider's various logo designs","The SLA review primarily determines which employees of the customer may travel to the provider's head offices","Examining the SLA is needed mainly to estimate the provider's total annual electricity costs for its data centers too","The provider's availability and recovery guarantees directly affect the customer's own ability to meet its objectives"], correct:3, explanation:"Logos, travel, and the provider's power costs are irrelevant; the provider's resilience and SLA commitments directly affect the customer's objectives." },
  { id:21157, domain:4, level:2, question:"What is the primary purpose of quality assurance (QA) in IT operations?", options:["Verifying that processes and deliverables meet defined standards and requirements before they are released","Increasing the marketing budget allocated to promoting the organization's newest software product releases","Determining the seating plan for the staff within the quality assurance department's open office area","Selecting the catering menu served at the organization's quarterly all-hands company-wide meetings"], correct:0, explanation:"Marketing budgets, seating, and catering are unrelated; QA verifies that processes and deliverables meet defined standards before release." },
  { id:21158, domain:4, level:3, question:"How does effective QA contribute to operational resilience?", options:["QA guarantees that no system will ever fail at all, completely eliminating the need for any recovery planning in turn","Catching defects and process weaknesses early reduces the likelihood of failures that disrupt operations later","QA exists primarily to slow down releases so that the operations staff have much more idle time available","QA contributes to resilience only by increasing the total number of documents stored in the records system"], correct:1, explanation:"QA does not guarantee zero failures, slow releases pointlessly, or just add documents; catching defects early reduces disruptive failures later." },
  { id:21159, domain:4, level:2, question:"Why should an organization audit a cloud provider's compliance with agreed controls?", options:["Auditing the provider is required mainly so the customer can negotiate a discount on next year's subscription fee too","The audit primarily determines which of the provider's data centers the customer's workloads will be hosted in","The customer remains accountable for its data, so it must obtain assurance that provider controls operate effectively","Auditing the provider exists chiefly to give the customer's audit team a reason to travel to the provider site"], correct:2, explanation:"Discounts, hosting location, and travel are not the point; the customer stays accountable for its data and needs assurance provider controls work." },
  { id:21160, domain:4, level:3, question:"An organization moves a critical workload to the cloud but keeps no exit or portability plan. What resilience risk does this create?", options:["Cloud workloads can never be migrated under any circumstances, so an exit plan would serve no useful purpose","The absence of an exit plan automatically violates every data protection regulation in force around the world","Keeping no exit plan guarantees that the cloud provider will lower its prices to retain the customer's business as noted","Vendor lock-in could make recovery or migration difficult if the provider fails or the relationship ends abruptly"], correct:3, explanation:"Migration is possible, no universal regulation is breached, and prices are not affected; lacking an exit plan creates lock-in and recovery risk." },
  { id:21161, domain:4, level:2, question:"Why should service continuity be considered when selecting a cloud service provider?", options:["A provider outage directly affects the customer's services, so the provider's continuity capability must be assessed","The provider's continuity plan merely determines the brand of the laptops the customer will issue to its own employees","Considering continuity is required mainly so the procurement document reaches a minimum required page length","Service continuity considerations exist chiefly to give the legal team additional clauses to negotiate over"], correct:0, explanation:"Laptop brand, page length, and legal busywork are irrelevant; a provider outage affects customer services, so its continuity capability matters." },
  { id:21162, domain:4, level:2, question:"What is a key benefit of automating routine operational tasks such as backups and monitoring?", options:["Automation completely eliminates the need to ever review whether the automated tasks are running correctly","Automation reduces human error and ensures tasks run consistently even when staff are unavailable or distracted","Automating tasks primarily reduces the data center's electricity bill by powering down idle servers each night over time","Automation exists chiefly so that the operations team can be reduced to a single staff member overall"], correct:1, explanation:"Eliminating review, power savings, and a one-person team are wrong; automation reduces human error and ensures consistent execution." },
  { id:21163, domain:4, level:2, question:"Why should an IS auditor evaluate the effectiveness of monitoring and alerting as part of an operations review?", options:["Monitoring is evaluated mainly so the auditor can recommend a specific brand of monitoring tool to purchase","Evaluating monitoring primarily determines how many analysts should be seated in the operations control room up front","Effective monitoring enables early detection and response, directly affecting availability and incident impact","The evaluation exists chiefly to lengthen the audit report so that it appears more thorough to management"], correct:2, explanation:"Tool brand, seating, and report length are not the point; effective monitoring enables early detection and response, affecting availability." },
  { id:21164, domain:4, level:2, question:"Why is segregation of duties between operations and security monitoring beneficial?", options:["It ensures that operations staff and security staff are always seated on entirely separate office floors","It guarantees that the monitoring tools will run noticeably faster because fewer people are logged in","It primarily determines which team is permitted to order new coffee supplies for the shared break room","It prevents an operator who causes an issue from also controlling the logs that would reveal the action"], correct:3, explanation:"Floor seating, tool speed, and coffee are irrelevant; separating these duties stops an operator from controlling the logs that record their actions." },
  { id:21165, domain:4, level:1, question:"What is a configuration item (CI) in service management?", options:["Any component such as a server, application, or document that must be managed to deliver an IT service","A printed marketing flyer describing the IT services that are available to external paying customers for them","A single line of source code written by a developer during an application enhancement project","An employee identification badge issued to staff who work shifts inside the primary data center"], correct:0, explanation:"A flyer, code line, and badge are not CIs; a configuration item is any managed component needed to deliver an IT service." },
  { id:21166, domain:4, level:2, question:"Why should the relationship between RTO and the cost of recovery solutions be understood?", options:["Shorter RTOs are always free to achieve, so cost should never factor into the recovery strategy decision","Shorter RTOs generally require more costly solutions, so objectives must be balanced against affordable investment","Longer RTOs always cost more than shorter ones, so the cheapest option is always the fastest one available as a rule","RTO and recovery cost are entirely unrelated, so the two should never be considered together in planning"], correct:1, explanation:"RTO and cost are related, shorter is not free, and longer is not costlier; aggressive RTOs cost more, so objectives must be balanced against budget." },
  { id:21167, domain:4, level:3, question:"An IS auditor finds that recovery procedures were last updated before a major infrastructure migration. What is the PRIMARY concern?", options:["The procedures may now be printed using a font style that no longer matches the corporate documentation standard too","The procedures may have become slightly longer than necessary after the infrastructure migration was completed","The outdated procedures may not reflect the current environment and could fail when executed during a real disaster","The procedures may reference a recovery site that is now located too far from the staff members' homes"], correct:2, explanation:"Font, length, and travel distance are trivial; outdated procedures may not match the current environment and could fail during real recovery." },
  { id:21168, domain:4, level:2, question:"Why is it important to test backups taken from virtualized environments specifically?", options:["Virtual machine backups are always smaller than physical backups, so they never require any restore testing","Virtual machine backups cannot be encrypted, so restore testing is the only available protection method for them too","Virtual machine backups automatically delete themselves, so they must be tested immediately before they vanish","Virtual machine backups can capture inconsistent states, so restore testing confirms the machines boot and function"], correct:3, explanation:"Smaller size, no encryption, and self-deletion are false; VM backups can capture inconsistent states, so restore testing confirms they boot and work." },
  { id:21169, domain:4, level:1, question:"What is meant by recovery testing in the context of resilience?", options:["Exercising recovery procedures to confirm that systems and data can actually be restored as intended","Permanently deleting old recovery documentation so that only the newest version is ever retained","Measuring the physical temperature of the recovery site's server room during normal daily operations","Counting how many staff members are formally assigned to the disaster recovery team this year"], correct:0, explanation:"Deletion, temperature, and headcount are unrelated; recovery testing exercises procedures to confirm systems and data can actually be restored." },
  { id:21170, domain:4, level:2, question:"Why should change management and configuration management work together?", options:["Combining the two processes mainly reduces the number of staff required to operate the service desk team in turn","Recording changes against configuration items keeps the CMDB accurate and supports impact analysis and recovery","Linking them primarily determines the color coding used on the change advisory board's meeting agenda","Working together exists chiefly to lengthen the combined process documentation reviewed during audits"], correct:1, explanation:"Staff reduction, color coding, and document length are not the point; recording changes against CIs keeps the CMDB accurate for impact analysis and recovery." },
  { id:21171, domain:4, level:3, question:"An organization's monitoring generates many alerts but few are actionable. What improvement should the IS auditor MOST likely recommend?", options:["Disabling all alerting entirely so that staff are never disturbed by any notifications during their shifts each time","Hiring many more analysts so the existing flood of non-actionable alerts can all be reviewed manually","Tuning alert thresholds and correlation so that alerts are meaningful and staff can respond to genuine issues","Increasing the alert volume further so that no potential issue could ever possibly be missed by the team"], correct:2, explanation:"Disabling alerts, mass hiring, and more volume worsen things; tuning thresholds and correlation makes alerts meaningful and actionable." },
  { id:21172, domain:4, level:2, question:"Why is documenting interdependencies between systems important for resilience?", options:["Documenting dependencies is required mainly so the architecture diagram looks more detailed and impressive","Dependency documentation primarily determines which systems are physically placed nearest the data center door as noted","Interdependency records exist chiefly to give the configuration team more diagrams to maintain each quarter","A failure or recovery of one system can affect others, so dependencies must be understood to plan recovery order"], correct:3, explanation:"Impressive diagrams, physical placement, and busywork are not the point; dependencies must be understood to plan recovery order and impact." },
  { id:21173, domain:4, level:1, question:"What is the purpose of a recovery site readiness assessment?", options:["Confirming that the alternate site has the equipment, connectivity, and capacity needed to support recovery","Determining which catering company will provide meals to the recovery team during a declared disaster","Measuring the resale value of the recovery site building should the organization decide to sell it later by design","Counting the number of parking spaces available for staff who travel to the recovery site each day"], correct:0, explanation:"Catering, resale value, and parking are unrelated; a readiness assessment confirms the site can actually support recovery with needed resources." },
  { id:21174, domain:4, level:2, question:"Why should an organization maintain offsite copies of its recovery documentation?", options:["Offsite documentation copies are required mainly so the recovery binder appears thicker and more complete","If the primary site is destroyed, responders still need accessible procedures to carry out the recovery","Keeping copies offsite primarily reduces the storage space consumed within the primary data center facility","Offsite documentation exists chiefly so the audit team has additional copies to review during fieldwork"], correct:1, explanation:"A thicker binder, storage savings, and audit copies are not the point; if the primary site is destroyed, responders still need accessible procedures." },
  { id:21175, domain:4, level:3, question:"An IS auditor finds that critical system administrators have no documented backups for their roles. What resilience risk does this MOST create?", options:["The administrators may feel overworked and could request additional compensation for their specialized duties up front","The organization may need to purchase additional desks to seat the backup administrators once they are hired","A single person's absence could prevent recovery or operation, creating a key-person dependency during a crisis","The administrators may use slightly different procedures than their eventual replacements would later use"], correct:2, explanation:"Compensation, desks, and minor procedure differences are not the risk; lacking role backups creates a key-person dependency that threatens recovery." },
  { id:21176, domain:4, level:2, question:"Why is capacity management relevant to resilience and continuity?", options:["Capacity management is relevant mainly because it determines the color of the capacity planning dashboard","Capacity planning primarily decides which staff members are assigned to the night shift in the data center in practice","Capacity management exists chiefly so the operations team has additional charts to present at meetings","Insufficient capacity at a recovery site could prevent it from handling production load during a real disaster"], correct:3, explanation:"Dashboard color, shift assignment, and charts are not the point; insufficient recovery-site capacity could prevent handling production load in a disaster." },
  { id:21177, domain:4, level:1, question:"What is the purpose of a service request in service management?", options:["Handling a user's standard, pre-approved request for a service such as access or equipment provisioning","Reporting an unexpected interruption to a live service that requires urgent restoration by the support team","Documenting the root cause of a recurring problem so that it can be permanently eliminated over time","Authorizing a high-risk change to the production environment after a full advisory board review process"], correct:0, explanation:"An interruption is an incident, root cause is a problem, and high-risk change needs CAB; a service request handles standard, pre-approved user requests." },
  { id:21178, domain:4, level:2, question:"Why should privileged actions performed during recovery be logged?", options:["Logging recovery actions is required mainly so the recovery report reaches a minimum acceptable page count as a rule","Logging supports accountability and allows later review of what was changed during the high-pressure recovery effort","Recovery logs primarily determine which team member is credited with completing the recovery the fastest","Logging exists chiefly so that the recovery team has additional files to archive once the crisis has ended"], correct:1, explanation:"Page count, crediting speed, and archiving are not the point; logging privileged recovery actions supports accountability and later review." },
  { id:21179, domain:4, level:3, question:"An organization performs frequent backups but stores them on the same storage array as production. What is the GREATEST weakness?", options:["The backups will consume slightly more space on the array than if they were compressed before being stored at times","The backup process may run marginally slower because it shares the array with the production workload","A failure or compromise of that single array could destroy both production data and its backups at the same time","The backups may use a different file naming convention than the production data stored on the same array"], correct:2, explanation:"Storage space, speed, and naming are minor; co-locating backups with production means one array failure can destroy both copies together." },
  { id:21180, domain:4, level:2, question:"Why is a clear incident severity classification scheme important?", options:["A severity scheme is important mainly because it adds more colorful labels to the incident ticketing system too","Severity classification primarily determines which support analyst is allowed to leave the office earliest","A severity scheme exists chiefly to increase the number of mandatory fields staff must complete per ticket","It ensures consistent prioritization so that high-impact incidents receive appropriate urgency and escalation"], correct:3, explanation:"Colorful labels, early leaving, and extra fields are not the point; a severity scheme ensures consistent prioritization and appropriate escalation." },
  { id:21181, domain:4, level:1, question:"What is the purpose of monitoring environmental conditions in a data center?", options:["Detecting temperature, humidity, or power problems early to prevent equipment damage and unplanned outages","Determining which background music should be played in the data center during regular business hours","Measuring how many visitors tour the data center each month for the organization's marketing reports","Counting the number of empty rack spaces available for future expansion of the server estate over time as well"], correct:0, explanation:"Music, visitor counts, and empty racks are unrelated; environmental monitoring detects conditions that could damage equipment and cause outages." },
  { id:21182, domain:4, level:2, question:"Why should an organization regularly reconcile its asset inventory against actual deployed assets?", options:["Reconciling the inventory is required mainly so the asset spreadsheet has more rows to display each quarter","Reconciliation detects missing, untracked, or unauthorized assets that could create security or recovery gaps","Asset reconciliation primarily determines which department receives the newest equipment in the next refresh","Reconciliation exists chiefly so the asset team has a recurring task to perform during otherwise quiet periods"], correct:1, explanation:"More rows, equipment allocation, and busywork are not the point; reconciliation detects missing or unauthorized assets that create gaps." },
  { id:21183, domain:4, level:3, question:"A critical application has no defined RPO or RTO. What is the PRIMARY consequence for resilience planning?", options:["The application will automatically be assigned the longest possible recovery times by the recovery software","The absence of objectives guarantees that the application can never actually be recovered after any disaster","Without these objectives, recovery strategies and backup frequency cannot be properly designed or evaluated","The application will consume more storage because undefined objectives force continuous full backups daily"], correct:2, explanation:"Auto-assignment, guaranteed non-recovery, and forced full backups are false; without RPO and RTO, recovery strategies cannot be properly designed." },
  { id:21184, domain:4, level:2, question:"Why should patch deployment be tracked and reported on?", options:["Patch tracking is required mainly so the patch report document appears longer and more detailed to readers as noted","Tracking patches primarily determines which administrator is assigned to apply the next round of updates","Patch reporting exists chiefly so the security team has additional statistics to present in team meetings","Tracking shows which systems remain unpatched, supporting risk management and demonstrating remediation progress"], correct:3, explanation:"A longer report, assignment, and meeting stats are not the point; tracking shows unpatched systems and demonstrates remediation progress." },
  { id:21185, domain:4, level:1, question:"What is failover in a high-availability design?", options:["The automatic or manual switch of operations to a standby component when the primary one fails or degrades","The permanent shutdown of a system once it has reached the end of its useful operational lifecycle","The scheduled rotation of backup tapes between the primary site and the offsite storage facility weekly by design","The process of compressing data so that it occupies less space on the production storage subsystem"], correct:0, explanation:"Shutdown, tape rotation, and compression are unrelated; failover switches operations to a standby component when the primary fails or degrades." },
  { id:21186, domain:4, level:2, question:"Why is it important that recovery strategies address both data and processing capability?", options:["Addressing both is required mainly so the recovery plan document reaches its expected total page length over time","Restoring data alone is insufficient if no systems exist to process it, so both must be planned together","Data and processing are addressed together primarily to reduce the size of the recovery team needed","Planning both exists chiefly to give the continuity team more sections to populate in the plan template"], correct:1, explanation:"Page length, team size, and template sections are not the point; restored data is useless without systems to process it, so both must be planned." },
  { id:21187, domain:4, level:3, question:"An IS auditor observes that DR test scope excludes network connectivity to the recovery site. What is the MOST significant gap?", options:["The DR test report will be slightly shorter because one section of testing was omitted from the exercise up front","The recovery team will have fewer tasks to perform, which may make the test finish ahead of schedule","Recovered systems may be unreachable in a real disaster because connectivity was never actually validated","The recovery site may appear less busy during the test than it would during an actual disaster event"], correct:2, explanation:"A shorter report, fewer tasks, and appearance are trivial; untested connectivity means recovered systems may be unreachable in a real disaster." },
  { id:21188, domain:4, level:2, question:"Why should access to production environments be more tightly controlled than access to development?", options:["Development environments are always larger than production, so they naturally require fewer access controls","Production access must be tighter only because production servers are physically heavier than development ones for them","Production is controlled more tightly mainly so the access list document is shorter and easier to review","Production holds live data and supports real business operations, so unauthorized access carries far greater impact"], correct:3, explanation:"Size, weight, and document length are irrelevant; production holds live data and operations, so unauthorized access there has far greater impact." },
  { id:21189, domain:4, level:1, question:"What is the purpose of an escalation procedure in incident management?", options:["Defining when and to whom an unresolved or high-impact incident is referred for additional support or authority","Determining the order in which staff are served lunch in the cafeteria during major incident response efforts for them","Calculating the overtime owed to support staff who work beyond their scheduled hours during an incident","Recording the personal contact details of customers so they can be invited to company social events"], correct:0, explanation:"Lunch order, overtime, and social events are unrelated; an escalation procedure defines when and to whom incidents are referred for more support." },
  { id:21190, domain:4, level:2, question:"Why should an organization define maximum acceptable outage durations for its services?", options:["Defining outage durations is required mainly so the continuity policy document looks more complete to readers as a rule","These thresholds drive recovery investment and prioritization so the most critical services are restored first","Outage thresholds primarily determine which conference room the continuity committee will meet in each month","Defining durations exists chiefly so the continuity team has additional numbers to track on its dashboards"], correct:1, explanation:"A complete-looking policy, room booking, and dashboard numbers are not the point; outage thresholds drive recovery investment and prioritization." },
  { id:21191, domain:4, level:3, question:"An organization relies on a single internet service provider for all connectivity. What resilience weakness exists?", options:["A single provider always charges more than using two providers, so the arrangement is purely a cost concern at times","Using one provider means the network team has fewer vendor relationships to document for the audit team","The single provider is a point of failure whose outage could sever all connectivity until service is restored","The single provider arrangement mainly affects the color of the status icons on the network dashboard"], correct:2, explanation:"Cost, vendor count, and icon color are minor; a single provider is a point of failure that can sever all connectivity during an outage." },
  { id:21192, domain:4, level:2, question:"Why is it important to verify that backup jobs complete successfully and not just that they are scheduled?", options:["Verifying completion is required mainly so the backup log file grows large enough to appear thorough","Completion verification primarily determines which operator is assigned to monitor backups the following week too","Confirming completion exists chiefly so the backup team has additional checkmarks to record each morning","A scheduled job that silently fails leaves no usable backup, so completion must be confirmed for real protection"], correct:3, explanation:"A large log, assignment, and checkmarks are not the point; a scheduled job that silently fails leaves no usable backup, so completion must be confirmed." },
  { id:21193, domain:4, level:1, question:"What is the role of a problem record in service management?", options:["Documenting an underlying cause of one or more incidents so it can be investigated and permanently resolved","Recording a user's standard request for new equipment or access to a particular business application as well","Authorizing an emergency change to the production environment during an active major service outage","Logging the physical entry and exit of visitors to the primary data center during business hours"], correct:0, explanation:"A standard request, change authorization, and visitor log are different; a problem record documents an underlying cause for investigation and resolution." },
  { id:21194, domain:4, level:2, question:"Why should an organization periodically review and update its business continuity plan?", options:["Reviewing the plan is required mainly so the continuity document is reprinted on fresh paper each year","Organizational, technological, and risk changes can make a plan obsolete, so reviews keep it relevant and effective","Periodic reviews primarily determine which staff member is named as the continuity coordinator that year","Updating the plan exists chiefly to keep the continuity team occupied during otherwise quiet business periods in turn"], correct:1, explanation:"Reprinting, naming a coordinator, and busywork are not the point; changes in the organization, technology, and risk can make a plan obsolete." },
  { id:21195, domain:4, level:3, question:"An IS auditor finds that recovery responsibilities overlap among several teams with no clear lead. What is the PRIMARY risk?", options:["The overlap will simply make the recovery plan document slightly longer because more teams are listed in it","Multiple teams being involved guarantees that recovery will always be completed faster than with a single team each time","Unclear ownership could cause confusion, duplicated effort, or gaps that delay recovery during an actual disaster","The overlap mainly affects how the recovery organization chart is laid out in the continuity documentation"], correct:2, explanation:"A longer document, guaranteed speed, and chart layout are wrong; unclear ownership risks confusion, duplication, or gaps that delay recovery." },
  { id:21196, domain:4, level:2, question:"Why is monitoring of replication status important in a resilient architecture?", options:["Replication monitoring is required mainly so the replication dashboard displays additional colorful charts","Monitoring replication primarily determines which administrator is credited with configuring it originally","Replication status is monitored chiefly so the storage team has more metrics to report each month","A silent replication failure could leave the recovery copy stale, so its health must be actively monitored"], correct:3, explanation:"Colorful charts, crediting, and report metrics are not the point; a silent replication failure could leave the recovery copy stale and unusable." },
  { id:21197, domain:4, level:1, question:"What is the purpose of a maintenance window in IT operations?", options:["Providing a scheduled period to perform changes or maintenance with reduced impact on business operations","Determining the hours during which the data center's cooling system is permitted to operate each day","Setting the times at which operations staff are allowed to take their scheduled breaks during a shift","Recording the dates on which the organization holds its quarterly all-hands company-wide staff meetings by design"], correct:0, explanation:"Cooling hours, break times, and meetings are unrelated; a maintenance window is a scheduled period for changes or maintenance with reduced impact." },
  { id:21198, domain:4, level:2, question:"Why should an organization assess the resilience of key suppliers as part of continuity planning?", options:["Assessing suppliers is required mainly so the procurement file contains more documents for the auditors to review","A critical supplier's failure could disrupt the organization's own operations, so supplier resilience must be","Supplier assessments primarily determine which vendor receives the largest booth at the company's trade event","Evaluating suppliers exists chiefly to give the procurement team additional vendors to add to its database"], correct:1, explanation:"Audit documents, booth size, and database entries are not the point; a critical supplier's failure could disrupt operations, so resilience must be assessed." },
  { id:21199, domain:4, level:3, question:"An organization's BCP focuses entirely on IT recovery and ignores people, facilities, and processes. What is the PRIMARY weakness?", options:["Focusing only on IT makes the BCP document shorter, which mainly affects how long it takes auditors to read","An IT-only focus guarantees that the organization's technology will recover faster than any of its competitors up front","Continuity requires more than IT, so ignoring staff, premises, and processes leaves the organization unable to operate","The narrow focus mainly determines which department is assigned to maintain the continuity plan going forward"], correct:2, explanation:"Document length, competitor speed, and plan ownership are not the point; continuity needs people, facilities, and processes, not IT alone." },
  { id:21200, domain:4, level:2, question:"Why should an organization classify its systems by criticality before designing recovery strategies?", options:["Classifying systems by criticality is required mainly so the inventory list displays additional descriptive columns","System criticality primarily determines which administrator is assigned to maintain each system going forward","Classification exists chiefly so the operations team has more categories to use when labeling its equipment","Criticality classification directs limited recovery resources toward the systems whose loss most harms the business"], correct:3, explanation:"Extra columns, assignment, and labels are not the point; criticality classification directs limited recovery resources to the systems whose loss most harms the business." }
];
if (typeof window !== 'undefined') window.QUESTIONS_CISA_C4 = QUESTIONS_CISA_C4;
